                    VectorStore.addDocuments(key, doc.content, activeKeyProfile.key).catch(e => console.warn("Background Vectorization:", e));
                }
            } else {
                setKnowledgeBase(null);
                setKnowledgeFileName(null);
            }
        } catch (e) {
            console.error("Failed to load KB from DB", e);
