    }, [isAutoCheckEnabled, isAnalyzeLoading, isOcrLoading, isReportLoading, isCheckingKey, apiKeys]);

    const performBackgroundHealthCheck = async () => {
        const sortedKeys = [...apiKeys].sort((a, b) => new Date(a.lastChecked || 0).getTime() - new Date(b.lastChecked || 0).getTime());
        const candidate = sortedKeys[0]; if (!candidate) return;
        setApiKeys(prev => prev.map(k => k.id === candidate.id ? { ...k, status: 'checking' } : k));
        const cap = await determineKeyCapabilities(candidate.key);
        const today = new Date().toISOString().split('T')[0];
        setApiKeys(prev => prev.map(k => k.id === candidate.id ? { ...k, status: cap.status, activeModel: cap.activeModel || k.activeModel, latency: cap.latency, lastChecked: new Date().toISOString(), lastResetDate: today } : k));
    };

    const dismissError = () => { setIsErrorClosing(true); setTimeout(() => { setAiError(null); setIsErrorClosing(false); }, 300); };

    const handleGenericError = (e: any) => {
        const msg = e.message || "Unknown error";
        if (msg.includes("ALL_KEYS_EXHAUSTED")) { setAiError("All API Keys have been exhausted or Quota exceeded."); setShowSettingsModal(true); }
        else if (msg.includes("API Key is missing")) { setToastMsg("API Key is required. Please check settings."); setShowSettingsModal(true); }
        else setAiError(msg);
    };

    const insertTextAtCursor = (textToInsert: string) => {
        if (evidenceTextareaRef.current) {
            const textarea = evidenceTextareaRef.current;
            const start = textarea.selectionStart; const end = textarea.selectionEnd; const currentText = textarea.value;
            const textWithBreaks = `\n${textToInsert.trim()}\n`;
            const newValue = currentText.substring(0, start) + textWithBreaks + currentText.substring(end);
            setEvidence(newValue);
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
            setTimeout(() => { if (evidenceTextareaRef.current) { evidenceTextareaRef.current.focus(); evidenceTextareaRef.current.setSelectionRange(start + textWithBreaks.length, start + textWithBreaks.length); } }, 100);
        } else {
            setEvidence(prev => prev + "\n" + textToInsert.trim());
            if (layoutMode !== 'evidence') setLayoutMode('evidence');
        }
    };

    const determineKeyCapabilities = async (key: string): Promise<{ status: 'valid' | 'invalid' | 'quota_exceeded' | 'referrer_error' | 'unknown', activeModel?: string, latency: number, errorMessage?: string }> => {
        const result = await validateApiKey(key);
        let status: 'valid' | 'invalid' | 'quota_exceeded' | 'referrer_error' | 'unknown' = 'unknown';
        if (result.isValid) status = 'valid';
        else if (result.errorType === 'network_error') status = 'unknown'; 
        else if (result.errorType) status = result.errorType as any;

        return { 
            status, 
            activeModel: result.activeModel, 
            latency: result.latency, 
            errorMessage: result.errorMessage 
        };
    };

    const checkAllKeys = async (initialKeys: ApiKeyProfile[]) => {
        setIsCheckingKey(true); 
        setApiKeys(prev => prev.map(k => ({ ...k, status: 'checking' })));
        const today = new Date().toISOString().split('T')[0]; 
        const updatedKeys = [...initialKeys];
        for (let i = 0; i < updatedKeys.length; i++) {
            const profile = updatedKeys[i]; 
            const cap = await determineKeyCapabilities(profile.key);
            updatedKeys[i] = { 
                ...profile, 
                status: cap.status, 
                activeModel: cap.activeModel, 
                latency: cap.latency, 
                lastChecked: new Date().toISOString(), 
                lastResetDate: today 
            };
            setApiKeys(prev => {
                const newArr = [...prev];
                const idx = newArr.findIndex(k => k.id === profile.id);
                if (idx !== -1) newArr[idx] = updatedKeys[i];
                return newArr;
            });
            await new Promise(r => setTimeout(r, 100));
        }
        setApiKeys(currentKeys => {
            const currentActiveProfile = currentKeys.find(k => k.id === activeKeyId);
            if (!currentActiveProfile || (currentActiveProfile.status !== 'valid' && currentActiveProfile.status !== 'unknown')) {
                const bestKey = currentKeys.filter(k => k.status === 'valid').sort((a, b) => a.latency - b.latency)[0];
                if (bestKey) { 
                    setActiveKeyId(bestKey.id); 
                    localStorage.setItem("iso_active_key_id", bestKey.id);
                    setTimeout(() => setToastMsg(`Auto-switched to healthy key: ${bestKey.label}`), 0); 
                } 
            }
            localStorage.setItem("iso_api_keys", JSON.stringify(currentKeys));
            return currentKeys;
        });
        setIsCheckingKey(false);
    };

    const handleRefreshStatus = async (id: string) => {
        const keyProfile = apiKeys.find(k => k.id === id); 
        if (!keyProfile) return;
        setApiKeys(prev => prev.map(k => k.id === id ? { ...k, status: 'checking' } : k));
        const cap = await determineKeyCapabilities(keyProfile.key);
        setApiKeys(prev => {
            const next = prev.map(k => k.id === id ? { 
                ...k, 
                status: cap.status, 
                activeModel: cap.activeModel || k.activeModel, 
                latency: cap.latency, 
                lastChecked: new Date().toISOString() 
            } : k);
            localStorage.setItem("iso_api_keys", JSON.stringify(next));
            return next;
        });
    };

    const handleAddKey = async () => {
        if (!newKeyInput.trim()) return;
        if (apiKeys.some(k => k.key === newKeyInput.trim())) { setToastMsg("This API Key is already in your pool!"); setNewKeyInput(""); return; }
        setIsCheckingKey(true); 
        const tempId = Date.now().toString(); 
        const cap = await determineKeyCapabilities(newKeyInput);
        const newProfile: ApiKeyProfile = { 
            id: tempId, 
            label: newKeyLabel || `Key ${apiKeys.length + 1}`, 
            key: newKeyInput, 
            status: cap.status, 
            activeModel: cap.activeModel, 
            latency: cap.latency, 
            lastChecked: new Date().toISOString(), 
            lastResetDate: new Date().toISOString().split('T')[0] 
        };
        const nextKeys = [...apiKeys, newProfile];
        setApiKeys(nextKeys);
        localStorage.setItem("iso_api_keys", JSON.stringify(nextKeys));
        if (apiKeys.length === 0 || (activeKeyProfile?.status !== 'valid' && cap.status === 'valid')) {
            setActiveKeyId(tempId);
            localStorage.setItem("iso_active_key_id", tempId);
        }
        setNewKeyInput(""); setNewKeyLabel(""); setIsCheckingKey(false);

        if(cap.status === 'valid') {
            setToastMsg("Key added successfully!");
        } else {
            setAiError(cap.errorMessage || "Connection failed. Please check your API Key and Network.");
        }
    };

    const handleDeleteKey = (id: string) => {
        const nextKeys = apiKeys.filter(k => k.id !== id);
        let newActiveId = activeKeyId;
        if (activeKeyId === id) {
            const nextBest = nextKeys.find(k => k.status === 'valid') || nextKeys[0];
            newActiveId = nextBest ? nextBest.id : "";
        }
        setApiKeys(nextKeys);
        if (newActiveId !== activeKeyId) setActiveKeyId(newActiveId);
        localStorage.setItem("iso_api_keys", JSON.stringify(nextKeys));
        if (newActiveId) localStorage.setItem("iso_active_key_id", newActiveId);
        else localStorage.removeItem("iso_active_key_id");
        setToastMsg("Key removed from pool.");
    };

    const executeWithSmartFailover = useCallback(async <T,>(operation: (apiKey: string, model: string) => Promise<T>): Promise<T> => {
        // If offline, bypass smart failover for keys and just execute the operation (which handles offline logic)
        if (!navigator.onLine) {
             return operation("offline", "local-model");
        }

        const candidates = apiKeys.filter(k => k.status !== 'invalid').sort((a, b) => {
            if (a.status === 'valid' && b.status !== 'valid') return -1;
            if (a.status !== 'valid' && b.status === 'valid') return 1;
            if (a.id === activeKeyId) return -1;
            if (b.id === activeKeyId) return 1;
            return a.latency - b.latency;
        });
        if (candidates.length === 0) throw new Error("API Key is missing or all keys are invalid.");
        let lastError: any;
        for (const profile of candidates) {
            const modelToUse = profile.activeModel || MODEL_HIERARCHY[0];
            try {
                if (profile.id !== activeKeyId) setActiveKeyId(profile.id);
                const result = await operation(profile.key, modelToUse);
                return result;
            } catch (error: any) {
                console.warn(`Key ${profile.label} failed on ${modelToUse}:`, error); lastError = error;
                const msg = (error.message || "").toLowerCase();
                if (msg.includes("429") || msg.includes("quota") || msg.includes("resource exhausted")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'quota_exceeded' } : k));
                else if (msg.includes("403") || msg.includes("key not valid") || msg.includes("permission denied")) setApiKeys(prev => prev.map(k => k.id === profile.id ? { ...k, status: 'invalid' } : k));
            }
        }
        throw new Error(lastError?.message || "ALL_KEYS_EXHAUSTED");
    }, [apiKeys, activeKeyId]);

    const loadSessionData = async () => {
        try {
            const session = localStorage.getItem("iso_session_data");
            const customStds = localStorage.getItem("iso_custom_standards");
            if (customStds) setCustomStandards(JSON.parse(customStds));
            if (session) {
                const data = JSON.parse(session);
                if (data.standardKey) {
                    setStandardKey(data.standardKey);
                    await loadKnowledgeForStandard(data.standardKey);
                }
                if (data.auditInfo) setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...data.auditInfo });
                if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
                if (data.evidence) setEvidence(data.evidence);
                if (data.matrixData) setMatrixData(data.matrixData); // Restore Matrix
                if (data.evidenceTags) setEvidenceTags(data.evidenceTags); 
                if (data.analysisResult) setAnalysisResult(data.analysisResult);
                if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
                if (data.finalReportText) setFinalReportText(data.finalReportText);
                setLastSavedTime(new Date().toLocaleTimeString());
                setToastMsg("Previous session restored.");
            }
        } catch (e) { console.error("Load failed", e); }
    };

    const handleUpdateStandard = (std: Standard) => { setCustomStandards(prev => ({ ...prev, [standardKey]: std })); setToastMsg("Standard updated successfully."); };
    const handleResetStandard = (key: string) => { setCustomStandards(prev => { const next = { ...prev }; delete next[key]; return next; }); setToastMsg("Standard reset to default."); };

    const handleKnowledgeUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; 
        if (!file) return; 

        if (!standardKey || standardKey === "ADD_NEW") {
            setToastMsg("Please select a Standard first before uploading a source document.");
            return;
        }

        setKnowledgeFileName(file.name);
        setToastMsg("Parsing Standard Document...");

        try {
            const text = await processSourceFile(file);
            setKnowledgeBase(text);
            setToastMsg(`Standard Loaded (${(text.length / 1024).toFixed(0)}KB). Saving...`);

            if (standardKey) {
                await saveKnowledgeToStorage(standardKey, text, file.name);
            }
        } catch (err: any) {
            setToastMsg(err.message);
            setKnowledgeFileName(null);
            setKnowledgeBase(null);
        }
    };

    const handleAddStandard = async (name: string, file: File | null) => {
        setShowAddStandardModal(false);
        const newKey = `CUSTOM_${Date.now()}`;
        let text = "";

        if (file) {
            setToastMsg("Processing document and extracting structure...");
            try {
                text = await processSourceFile(file);
                setKnowledgeBase(text);
                setKnowledgeFileName(file.name);
                await saveKnowledgeToStorage(newKey, text, file.name);

                setToastMsg("AI is analyzing structure... (This may take 15s)");

                try {
                    const parsedStandard = await executeWithSmartFailover((key, model) => parseStandardStructure(text, name, key, model));
                    if (parsedStandard) {
                        setCustomStandards(prev => ({ ...prev, [newKey]: parsedStandard }));
                        setStandardKey(newKey);
                        setToastMsg(`Successfully imported ${name} with full structure.`);
                        return; 
                    }
                } catch (parseError) {
                    console.error("AI Parse Failed, falling back to basic", parseError);
                    setToastMsg("AI parsing failed. Created basic structure instead.");
                }

            } catch (err: any) {
                setToastMsg(`File processing failed: ${err.message}`);
            }
        } else {
            setKnowledgeBase(null);
            setKnowledgeFileName(null);
        }

        const newStandard: Standard = {
            name: name,
            description: `Custom Standard created on ${new Date().toLocaleDateString()}`,
            groups: [{
                id: `GRP_${Date.now()}`,
                title: "General Requirements",
                icon: "Book",
                clauses: [
                    { id: `CL_${Date.now()}_1`, code: "1", title: "General", description: "Requirement details pending AI extraction." }
                ]
            }]
        };

        setCustomStandards(prev => ({ ...prev, [newKey]: newStandard }));
        setStandardKey(newKey);
        if (!file) setToastMsg(`Created basic standard: ${name}`);
    };

    // --- AUTO-SAVE LOGIC (Cleaned Up) ---
    useEffect(() => {
        if (isRestoring.current) return;
        const isEmptyState = !evidence && (!selectedClauses || selectedClauses.length === 0);
        if (isEmptyState && !isManuallyCleared.current) {
            if (localStorage.getItem("iso_session_data")) {
                return; // Don't overwrite existing data with initial empty state
            }
        }

        // Debounced Save
        const handler = setTimeout(() => {
            if (isRestoring.current) return;

            setIsSaving(true);
            const sessionData = { standardKey, auditInfo, selectedClauses, evidence, matrixData, evidenceTags, analysisResult, selectedFindings, finalReportText };
            localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            localStorage.setItem("iso_custom_standards", JSON.stringify(customStandards));
            localStorage.setItem("iso_api_keys", JSON.stringify(apiKeys));

            if (isManuallyCleared.current) isManuallyCleared.current = false;

            setLastSavedTime(new Date().toLocaleTimeString());
            // Short delay for visual feedback
            setTimeout(() => setIsSaving(false), 500);
        }, 1000); 

        return () => clearTimeout(handler);
    }, [standardKey, auditInfo, selectedClauses, evidence, matrixData, evidenceTags, analysisResult, selectedFindings, finalReportText, customStandards, apiKeys]);

    useEffect(() => {
        const handleBeforeUnload = (e: BeforeUnloadEvent) => {
            if (!isRestoring.current) {
                const sessionData = { standardKey, auditInfo, selectedClauses, evidence, matrixData, evidenceTags, analysisResult, selectedFindings, finalReportText };
                localStorage.setItem("iso_session_data", JSON.stringify(sessionData));
            }
        };
        window.addEventListener('beforeunload', handleBeforeUnload);
        return () => window.removeEventListener('beforeunload', handleBeforeUnload);
    }, [standardKey, auditInfo, selectedClauses, evidence, matrixData, evidenceTags, analysisResult, selectedFindings, finalReportText]);

    const handleNewSession = async (e?: any) => { 
        if(e) e.stopPropagation(); 
        if(!confirm("Start New Session? Current data will be moved to 'Backup Vault'.")) return; 
        try {
            const currentData = { standardKey, auditInfo, selectedClauses, evidence, matrixData, evidenceTags, analysisResult, selectedFindings, finalReportText };
            const hasData = evidence.trim().length > 0 || selectedClauses.length > 0;
            if (hasData) {
                const snapshot: SessionSnapshot = {
                    id: `backup_${Date.now()}`,
                    timestamp: Date.now(),
                    label: "Backup (Pre-Reset)",
                    triggerType: "MANUAL_BACKUP",
                    data: currentData
                };
                const historyRaw = localStorage.getItem("iso_session_history");
                const history = historyRaw ? JSON.parse(historyRaw) : [];
                const newHistory = [snapshot, ...history].slice(0, 5);
                localStorage.setItem("iso_session_history", JSON.stringify(newHistory));
            }
            isManuallyCleared.current = true;
            localStorage.removeItem("iso_session_data");
            setStandardKey("");
            setAuditInfo(DEFAULT_AUDIT_INFO); 
            setEvidence(""); 
            setMatrixData({});
            setEvidenceTags([]);
            setSelectedClauses([]); 
            setUploadedFiles([]); 
            setAnalysisResult(null); 
            setSelectedFindings({}); 
            setFinalReportText(null); 
            setLastSavedTime(null); 
            setSessionKey(Date.now());
            setKnowledgeBase(null); 
            setKnowledgeFileName(null);
            setLayoutMode('evidence'); 
            // Clear Cache on New Session
            analysisCache.current = {};
            setToastMsg("New Session Started. (Previous session archived in Recall)");
        } catch (error) {
            console.error("New Session Error", error);
            setToastMsg("Error creating backup. Session reset anyway.");
        }
    };

    const handleRestoreSnapshot = async (snapshot: SessionSnapshot) => {
        try {
            isRestoring.current = true;
            setShowRecallModal(false);
            const data = snapshot.data;
            localStorage.setItem("iso_session_data", JSON.stringify(data));
            if (data.standardKey) {
                setStandardKey(data.standardKey);
                await loadKnowledgeForStandard(data.standardKey);
            }
            setAuditInfo({ ...DEFAULT_AUDIT_INFO, ...(data.auditInfo || {}) });
            if (data.selectedClauses) setSelectedClauses(data.selectedClauses);
            if (data.evidence !== undefined) setEvidence(data.evidence);
            if (data.matrixData) setMatrixData(data.matrixData);
            if (data.evidenceTags) setEvidenceTags(data.evidenceTags);
            setUploadedFiles([]); 
            if (data.analysisResult) setAnalysisResult(data.analysisResult);
            if (data.selectedFindings) setSelectedFindings(data.selectedFindings);
            if (data.finalReportText) setFinalReportText(data.finalReportText);
            setSessionKey(Date.now());
            // Clear cache on restore to ensure fresh state if contexts mismatch
            analysisCache.current = {};
            const now = new Date();
            setLastSavedTime(now.toLocaleTimeString());
            setToastMsg(`Restored session from: ${new Date(snapshot.timestamp).toLocaleTimeString()}`);
            setTimeout(() => {
                isRestoring.current = false;
                isManuallyCleared.current = false; 
            }, 1200);
        } catch (e) {
            console.error("Restore failed", e);
            setToastMsg("Failed to restore session snapshot.");
            isRestoring.current = false;
        }
    };

    // Wrap Heavy Handlers with useCallback
    const handleOcrUpload = useCallback(async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;
        setIsOcrLoading(true); setLoadingMessage("Processing documents with Vision AI...");
        let processedCount = 0;
        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));
                let text = "";
                if (fileEntry.file.type === 'text/plain') text = await fileEntry.file.text();
                else {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await executeWithSmartFailover(async (key, model) => generateOcrContent("Extract all text.", base64, fileEntry.file.type, key, model));
                }
                if (text) {
                    const deptHeader = activeDepartment ? `\n[Dept: ${activeDepartment}]\n` : "";
                    const separator = `\n\n--- FILE: ${fileEntry.file.name} ---${deptHeader}\n`;
                    insertTextAtCursor(separator + text);
                    setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                    processedCount++;
                } else throw new Error("No text extracted");
            } catch (error: any) {
                console.error("OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsOcrLoading(false); setLoadingMessage(""); setToastMsg(`Processed ${processedCount} files.`);
    }, [uploadedFiles, executeWithSmartFailover, activeDepartment]);

    const handleTemplateUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0]; if (!file) return; setTemplateFileName(file.name);
        try {
            if (file.name.endsWith('.docx')) {
                if (typeof mammoth === 'undefined') { alert("Mammoth library not loaded for .docx support"); return; }
                const arrayBuffer = await file.arrayBuffer(); const result = await mammoth.extractRawText({ arrayBuffer }); setReportTemplate(result.value);
            } else { const text = await file.text(); setReportTemplate(text); }
            setToastMsg("Template loaded successfully.");
        } catch (err) { setToastMsg("Failed to load template."); console.error(err); }
    };

    const startSmartExport = (content: string, type: 'notes' | 'report' | 'evidence', lang: ExportLanguage) => {
        let exportContent = content;

        // SYNTHESIS: Combine Matrix Data for Evidence Export
        if (type === 'evidence') {
            const matrixString = serializeMatrixData(matrixData, selectedClauses);
            if (matrixString) {
                exportContent = `${content}\n\n${matrixString}`;
            }
        }

        if (!exportContent) return;
        const CHUNK_SIZE = 4000; const chunks = []; for (let i = 0; i < exportContent.length; i += CHUNK_SIZE) chunks.push(exportContent.substring(i, i + CHUNK_SIZE));
        setExportState({ isOpen: true, isPaused: false, isFinished: false, totalChunks: chunks.length, processedChunksCount: 0, chunks, results: new Array(chunks.length).fill(""), error: null, currentType: type, targetLang: lang });
    };

    // Handler to skip translation on failure
    const handleSkipExportChunk = () => {
        setExportState(prev => {
            const idx = prev.processedChunksCount;
            const newResults = [...prev.results];
            // Fallback: use original text for this chunk
            newResults[idx] = prev.chunks[idx];

            return {
                ...prev,
                isPaused: false,
                error: null,
                processedChunksCount: idx + 1, // Advance to next chunk
                results: newResults
            };
        });
    };

    const toggleAutoCheck = (enabled: boolean) => { setIsAutoCheckEnabled(enabled); localStorage.setItem('iso_auto_check', String(enabled)); setToastMsg(enabled ? "Auto-health check enabled." : "Auto-health check disabled."); };
    const handleStartEdit = (keyProfile: ApiKeyProfile) => { setEditingKeyId(keyProfile.id); setEditLabelInput(keyProfile.label); };
    const handleSaveLabel = () => { if (editingKeyId) { setApiKeys(prev => prev.map(k => k.id === editingKeyId ? { ...k, label: editLabelInput } : k)); setEditingKeyId(null); } };


    const handleOpenReferenceClause = async (clause: Clause) => {
        setReferenceClauseState({ isOpen: true, clause, isLoading: true, fullText: { en: "", vi: "" } });
        try {
            const text = await executeWithSmartFailover(async (key, model) => fetchFullClauseText(clause, allStandards[standardKey].name, knowledgeBase, key, model));
            setReferenceClauseState(prev => ({ ...prev, isLoading: false, fullText: text }));
        } catch (e: any) {
            setReferenceClauseState({ isOpen: false, clause: null, isLoading: false, fullText: { en: "", vi: "" } });
            setAiError("API Failed during lookup."); setShowSettingsModal(true); 
        }
    };

    const handleInsertReferenceText = (text: string) => {
        if (!referenceClauseState.clause) return;
        const quoteText = `\n--- REFERENCE: [${referenceClauseState.clause.code}] ${referenceClauseState.clause.title} ---\n${text}\n--- END REFERENCE ---\n`.trim();
        insertTextAtCursor(quoteText);
        setReferenceClauseState({ isOpen: false, clause: null, isLoading: false, fullText: { en: "", vi: "" } });
    };

    const handleAnalyze = useCallback(async () => {
        if (!standardKey) { setToastMsg("Select a Standard first."); return; }
        if (selectedClauses.length === 0) { setToastMsg("Select at least one Clause to analyze."); return; }
        if (!hasEvidence) { setToastMsg("No evidence provided. Please add text or files."); return; }

        setIsAnalyzeLoading(true);
        setLayoutMode('findings');
        // Do not clear analysisResult immediately, we append to it or update it.
        // But for a fresh "Analyze" click on a set, usually we expect fresh results for those specific clauses.
        // The previous logic cleared it: setAnalysisResult([]); 
        // We will clear it to avoid duplicates in UI for now, but in a real persistent app we might want to merge.
        setAnalysisResult([]);

        try {
             const allClausesFlat = allStandards[standardKey].groups.flatMap(g => g.clauses);
             const findClause = (id: string, list: Clause[]): Clause | undefined => {
                for (let c of list) { if (c.id === id) return c; if (c.subClauses) { const f = findClause(id, c.subClauses); if (f) return f; } }
             };

             const targets = selectedClauses.map(id => findClause(id, allClausesFlat)).filter(c => !!c) as Clause[];

             let fullEvidenceContext = evidence;

             uploadedFiles.filter(f => f.status === 'success' && f.result).forEach(f => {
                 fullEvidenceContext += `\n\n--- Document: ${f.file.name} ---\n${f.result}`;
             });

             const matrixString = serializeMatrixData(matrixData, selectedClauses);
             if (matrixString) {
                 fullEvidenceContext += `\n\n${matrixString}`;
             }

             let tagContext = "";
             evidenceTags.forEach(tag => {
                 tagContext += `[Tagged for ${tag.clauseId}]: "${tag.text}"\n`;
             });

             const privacyEnabled = localStorage.getItem('iso_privacy_shield') === 'true';

             // --- IDEMPOTENT CACHING SIGNATURE ---
             // Generate a hash of the entire context. If the text hasn't changed, the hash matches.
             const contextFingerprint = `${standardKey}_${privacyEnabled}_${generateContentHash(fullEvidenceContext + tagContext)}`;

             for (let i = 0; i < targets.length; i++) {
                 const clause = targets[i];
                 setCurrentAnalyzingClause(clause.code);

                 // Unique Key for this specific Analysis Instance (Clause + Context)
                 const findingKey = `${clause.id}_${contextFingerprint}`;

                 // 1. CHECK CACHE
                 if (analysisCache.current[findingKey]) {
                     console.log(`[Smart Cache] Hit for ${clause.code}`);
                     setAnalysisResult(prev => [...(prev || []), analysisCache.current[findingKey]]);
                     setSelectedFindings(prev => ({...prev, [clause.code]: true}));
                     // Yield to UI loop briefly
                     await new Promise(r => setTimeout(r, 10)); 
                     continue; 
                 }

                 setLoadingMessage(`Analyzing [${clause.code}] ${clause.title}...`);

                 try {
                     const jsonStr = await executeWithSmartFailover((key, model) => 
                        generateAnalysis(
                            { code: clause.code, title: clause.title, description: clause.description },
                            allStandards[standardKey].name,
                            fullEvidenceContext.substring(0, 50000), 
                            tagContext, 
                            key, 
                            model,
                            privacyEnabled 
                        )
                     );

                     const parsed = cleanAndParseJSON(jsonStr);
                     let newFinding: AnalysisResult;

                     if (parsed && typeof parsed === 'object') {
                         newFinding = {
                             clauseId: clause.code, 
                             status: parsed.status || 'N_A',
                             reason: parsed.reason || 'No reasoning provided.',
                             evidence: parsed.evidence || '',
                             suggestion: parsed.suggestion || '',
                             conclusion_report: parsed.conclusion_report || '',
                             crossRefs: parsed.crossRefs || []
                         };
                     } else {
                         newFinding = {
                             clauseId: clause.code,
                             status: 'N_A',
                             reason: 'AI failed to format response.',
                             evidence: '',
                             suggestion: '',
                             conclusion_report: '',
                             crossRefs: []
                         };
                     }

                     // 2. STORE IN CACHE
                     analysisCache.current[findingKey] = newFinding;

                     setAnalysisResult(prev => [...(prev || []), newFinding]);
                     setSelectedFindings(prev => ({...prev, [clause.code]: true})); 
                     await new Promise(r => setTimeout(r, 50));

                 } catch (clauseError) {
                     console.error(`Error analyzing clause ${clause.code}`, clauseError);
                     setAnalysisResult(prev => [...(prev || []), {
                         clauseId: clause.code,
                         status: 'N_A',
                         reason: 'Analysis failed due to API error.',
                         evidence: '',
                         suggestion: 'Retry manually.',
                         conclusion_report: '',
                         crossRefs: []
                     }]);
                 }
             }

             setToastMsg(navigator.onLine ? `Analysis Complete.` : `Offline Analysis Complete.`);

        } catch (e: any) {
            handleGenericError(e);
        } finally {
            setIsAnalyzeLoading(false);
            setLoadingMessage("");
            setCurrentAnalyzingClause("");
        }
    }, [standardKey, selectedClauses, hasEvidence, evidence, uploadedFiles, matrixData, evidenceTags, allStandards, executeWithSmartFailover]);

    const handleGenerateReport = async () => {
        if (!analysisResult || analysisResult.length === 0) {
            setToastMsg("No findings available to report.");
            return;
        }

        const activeFindings = analysisResult.filter(r => selectedFindings[r.clauseId]);
        if (activeFindings.length === 0) {
            setToastMsg("Please select at least one finding to include in the report.");
            return;
        }

        setIsReportLoading(true);
        setLoadingMessage("Synthesizing Final Audit Report...");

        try {
            let fullContext = evidence;
            const matrixString = serializeMatrixData(matrixData, selectedClauses);
            if (matrixString) fullContext += `\n\n${matrixString}`;

            const report = await executeWithSmartFailover((key, model) => 
                generateTextReport({
                    company: auditInfo.company,
                    type: auditInfo.type,
                    auditor: auditInfo.auditor,
                    standard: allStandards[standardKey]?.name,
                    findings: activeFindings,
                    lang: exportLanguage,
                    fullEvidenceContext: fullContext 
                }, key, model)
            );

            setFinalReportText(report);
            setLayoutMode('report');
            setToastMsg("Report Generated Successfully.");
        } catch (e: any) {
            handleGenericError(e);
        } finally {
            setIsReportLoading(false);
            setLoadingMessage("");
        }
    };

    useEffect(() => {
        if (!exportState.isOpen || exportState.isPaused || exportState.isFinished) return;

        const processChunk = async () => {
            const idx = exportState.processedChunksCount;
            if (idx >= exportState.totalChunks) {
                setExportState(prev => ({ ...prev, isFinished: true }));
                try {
                    const getSafeName = (str: string) => cleanFileName(str || "Unknown");
                    const stdName = getSafeName(allStandards[standardKey]?.name);
                    const aType = getSafeName(auditInfo.type);
                    const smo = getSafeName(auditInfo.smo);
                    const company = getSafeName(auditInfo.company);
                    const dept = getSafeName(auditInfo.department);
                    const auditor = getSafeName(auditInfo.auditor);
                    const timestamp = new Date().toISOString().replace(/[:.]/g, '-');
                    const fileName = `${stdName}_${aType}_${smo}_${company}_${dept}_Audit_Note_${auditor}_${timestamp}.txt`;

                    const finalContent = exportState.results.join("");
                    const blob = new Blob([finalContent], { type: 'text/plain' });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = fileName; 
                    document.body.appendChild(a);
                    a.click();
                    document.body.removeChild(a);
                    URL.revokeObjectURL(url);
                } catch(e) { console.error("Download failed", e); }
                return;
            }

            if (idx > 0) {
                await new Promise(resolve => setTimeout(resolve, 1500));
            }

            const chunk = exportState.chunks[idx];
            try {
                let result = chunk;
                const targetLanguageName = exportState.targetLang === 'vi' ? 'Vietnamese' : 'English';
                const prompt = `Translate to ${targetLanguageName}. Keep formatting. ISO Audit Context.\n\nInput:\n"""${chunk}"""`;

                result = await executeWithSmartFailover(async (key, model) => {
                     const ai = new (await import('@google/genai')).GoogleGenAI({ apiKey: key });
                     const res = await ai.models.generateContent({ model: model, contents: prompt });
                     return res.text || chunk;
                });

                setExportState(prev => {
                    const newResults = [...prev.results];
                    newResults[idx] = result;
                    return { ...prev, processedChunksCount: idx + 1, results: newResults };
                });
            } catch (e: any) {
                console.error("Export Error", e);
                let errMsg = e.message || "Unknown error";
                try {
                    const jsonStart = errMsg.indexOf('{');
                    if (jsonStart !== -1) {
                        const jsonPart = errMsg.substring(jsonStart);
                        const parsed = JSON.parse(jsonPart);
                        if (parsed.error && parsed.error.message) {
                            errMsg = `API Error: ${parsed.error.message}`;
                        }
                    }
                } catch (ignore) {}

                setExportState(prev => ({ ...prev, isPaused: true, error: errMsg }));
            }
        };
        processChunk();
    }, [exportState, executeWithSmartFailover, standardKey, auditInfo, allStandards]);

    const handleResumeExport = async () => {
        setIsRescuing(true);
        try {
            if (rescueKey.trim()) {
                const result = await validateApiKey(rescueKey);
                const cap = { status: result.isValid ? 'valid' : (result.errorType || 'unknown'), errorMessage: result.errorMessage, activeModel: result.activeModel, latency: result.latency };

                if (cap.status === 'valid') {
                     const newProfile: ApiKeyProfile = { id: `rescue_${Date.now()}`, label: `Rescue Key`, key: rescueKey, status: 'valid', activeModel: cap.activeModel, latency: cap.latency as number, lastChecked: new Date().toISOString() };
                    setApiKeys(prev => [...prev, newProfile]);
                    setActiveKeyId(newProfile.id);
                    setToastMsg("Rescue Key Added. Resuming...");
                    setExportState(prev => ({ ...prev, isPaused: false, error: null }));
                    setRescueKey("");
                } else {
                    setToastMsg(`Rescue Key Invalid: ${cap.errorMessage}`);
                }
            } else {
                setExportState(prev => ({ ...prev, isPaused: false, error: null }));
            }
        } catch (e) {
            setToastMsg("Failed to resume.");
        } finally {
            setIsRescuing(false);
        }
    };

    useEffect(() => {
        const handleKeyDown = (e: KeyboardEvent) => { if ((e.metaKey || e.ctrlKey) && e.key === 'k') { e.preventDefault(); setIsCmdPaletteOpen(prev => !prev); } };
        window.addEventListener('keydown', handleKeyDown);
        return () => window.removeEventListener('keydown', handleKeyDown);
    }, []);

    const commandActions = useMemo(() => {
        const baseActions: any[] = [
            { label: "Analyze Compliance", desc: `Start AI analysis`, icon: "Wand2", shortcut: "AI", action: handleAnalyze },
            { label: "Validate API Key Pool", desc: "Check connection health", icon: "RefreshCw", action: () => { checkAllKeys(apiKeys); setToastMsg("Validating Neural Pool..."); } },
            { label: "Settings", desc: "Manage configuration", icon: "Settings", action: () => setShowSettingsModal(true) },
            { label: "Generate Report", desc: "Synthesize final report", icon: "FileText", action: handleGenerateReport },
            { label: "Toggle Dark Mode", desc: `Switch to ${isDarkMode ? 'Light' : 'Dark'}`, icon: isDarkMode ? "Sun" : "Moon", action: () => setIsDarkMode(!isDarkMode) },
        ];

        if (standardKey && allStandards[standardKey]) {
            const flatten = (list: Clause[]): Clause[] => list.reduce((acc, c) => {
                acc.push(c);
                if (c.subClauses) acc.push(...flatten(c.subClauses));
                return acc;
            }, [] as Clause[]);

            const allClauses = flatten(allStandards[standardKey].groups.flatMap(g => g.clauses));

            const clauseActions = allClauses.map(c => ({
                label: `[${c.code}] ${c.title}`,
                desc: c.description || "No description",
                icon: "Session6_Zap", 
                type: 'clause',
                action: () => {
                    const isSelected = selectedClauses.includes(c.id);
                    if (isSelected) setSelectedClauses(prev => prev.filter(id => id !== c.id));
                    else setSelectedClauses(prev => [...prev, c.id]);
                    insertTextAtCursor(`[${c.code}] ${c.title}`);
                    setToastMsg(`Inserted clause ${c.code} and ${isSelected ? 'removed from' : 'added to'} audit scope.`);
                    setIsCmdPaletteOpen(false);
                },
                onReference: (e: any) => {
                    if (e) e.stopPropagation();
                    handleOpenReferenceClause(c);
                    setIsCmdPaletteOpen(false);
                }
            }));
            return [...baseActions, ...clauseActions];
        }
        return baseActions;
    }, [isDarkMode, standardKey, allStandards, selectedClauses, activeKeyId, apiKeys, handleAnalyze]); 

    const displayBadge = useMemo(() => {
        const currentStandardName = allStandards[standardKey]?.name || "";
        const match = currentStandardName.match(/\((.*?)\)/);
        return match ? match[1] : (currentStandardName.split(' ')[0] || 'ISO');
    }, [standardKey, allStandards]);

    const badgeColorClass = useMemo(() => {
        const text = displayBadge.toUpperCase();
        if (text.includes('EMS') || text.includes('14001')) return "bg-emerald-100 dark:bg-emerald-900/40 text-emerald-700 dark:text-emerald-300 border-emerald-200 dark:border-emerald-700/50";
        if (text.includes('QMS') || text.includes('9001')) return "bg-blue-100 dark:bg-blue-900/40 text-blue-700 dark:text-blue-300 border-blue-200 dark:border-blue-700/50";
        if (text.includes('ISMS') || text.includes('27001')) return "bg-purple-100 dark:bg-purple-900/40 text-purple-700 dark:text-purple-300 border-purple-200 dark:border-purple-700/50";
        return "bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 dark:text-indigo-300 border-indigo-100 dark:border-indigo-800/50";
    }, [displayBadge]);

    const getAnalyzeTooltip = () => {
        if (isAnalyzeLoading) return "AI is analyzing...";
        const missing = [];
        if (selectedClauses.length === 0) missing.push("Clauses");
        if (!hasEvidence) missing.push("Evidence");
        return missing.length > 0 ? `Missing: ${missing.join(" & ")}` : "Click to Start AI Analysis";
    };

    return (
        <div className="flex flex-col h-[100dvh] w-full bg-gray-50 dark:bg-slate-900 transition-colors duration-500 ease-soft relative animate-fade-in-up">
            {toastMsg && <Toast message={toastMsg} onClose={() => setToastMsg(null)} />}

            {aiError && (
                <div className={`fixed z-[9999] top-20 left-4 right-4 md:left-auto md:right-5 md:w-96 md:max-w-sm bg-white dark:bg-slate-800 border-l-4 border-red-500 shadow-2xl rounded-r-xl p-4 animate-shake transition-all duration-300 ${isErrorClosing ? 'opacity-0 translate-x-4' : 'opacity-100 translate-x-0'}`}>
                    <div className="flex justify-between items-start">
                        <div className="flex items-center gap-2 text-red-600 dark:text-red-400 font-bold"><Icon name="AlertCircle" size={20}/><span>System Alert</span></div>
                        <button onClick={dismissError} className="text-gray-400 hover:text-slate-800 dark:hover:text-white transition-colors p-1 rounded-full hover:bg-gray-100 dark:hover:bg-slate-700"><Icon name="X" size={18}/></button>
                    </div>
                    <p className="text-sm text-slate-600 dark:text-slate-300 leading-relaxed mt-1">{aiError}</p>
                </div>
            )}

            <Header 
                isSidebarOpen={isSidebarOpen}
                setIsSidebarOpen={setIsSidebarOpen}
                displayBadge={displayBadge}
                badgeColorClass={badgeColorClass}
                setIsCmdPaletteOpen={setIsCmdPaletteOpen}
                fontSizeScale={fontSizeScale}
                setFontSizeScale={setFontSizeScale}
                isDarkMode={isDarkMode}
                setIsDarkMode={setIsDarkMode}
                isSystemHealthy={isSystemHealthy}
                onOpenSettings={() => setShowSettingsModal(true)}
                onOpenAbout={() => setShowAboutModal(true)}
            />

            <main className="flex-1 flex overflow-hidden relative">
                <div className={`${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'} fixed top-16 bottom-0 left-0 z-[60] md:absolute md:inset-y-0 md:relative md:top-0 md:translate-x-0 md:transform-none transition-transform duration-300 ease-soft h-[calc(100%-4rem)] md:h-full`}>
                    <Sidebar 
                        key={sessionKey} 
                        isOpen={isSidebarOpen} 
                        width={sidebarWidth} 
                        setWidth={setSidebarWidth} 
                        standards={allStandards} 
                        standardKey={standardKey} 
                        setStandardKey={handleSetStandardKey} 
                        auditInfo={auditInfo} 
                        setAuditInfo={setAuditInfo} 
                        selectedClauses={selectedClauses} 
                        setSelectedClauses={setSelectedClauses} 
                        onAddNewStandard={() => setShowAddStandardModal(true)} 
                        onUpdateStandard={handleUpdateStandard} 
                        onResetStandard={handleResetStandard} 
                        onReferenceClause={handleOpenReferenceClause} 
                        showIntegrityModal={showIntegrityModal} 
                        setShowIntegrityModal={setShowIntegrityModal}
                        knowledgeFileName={knowledgeFileName}
                        knowledgeBase={knowledgeBase} 
                        onKnowledgeUpload={handleKnowledgeUpload}
                        onClearKnowledge={handleClearKnowledge}
                    />
                </div>
                {isSidebarOpen && <div className="fixed top-16 bottom-0 inset-x-0 bg-black/50 z-50 md:hidden backdrop-blur-sm transition-opacity duration-300 animate-in fade-in" onClick={() => setIsSidebarOpen(false)} />}

                {/* --- MAIN CONTENT AREA --- */}
                <div className={`flex-1 flex flex-col min-w-0 relative w-full transition-all duration-300 ease-soft ${currentTabConfig.bgSoft} border-t-4 ${currentTabConfig.borderClass} will-change-transform`}>

                    <div className="flex-shrink-0 px-4 md:px-6 py-3 border-b border-gray-200 dark:border-slate-800 bg-white/80 dark:bg-slate-900/80 backdrop-blur flex justify-between items-center gap-3">
                        <div className="flex-1 min-w-0">
                            {/* REFACTORED: Tab Navigation Component */}
                            <TabNavigation 
                                layoutMode={layoutMode} 
                                setLayoutMode={setLayoutMode}
                                isSidebarOpen={isSidebarOpen}
                                sidebarWidth={sidebarWidth}
                            />
                        </div>
                        <div className="flex gap-2 items-center flex-shrink-0 pl-2 border-l border-gray-200 dark:border-slate-800">
                            <button 
                                onClick={() => setShowRecallModal(true)} 
                                className={`h-10 px-4 rounded-xl flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 border ${lastSavedTime ? 'bg-emerald-50 dark:bg-emerald-900/20 text-emerald-600 dark:text-emerald-400 border-emerald-200 dark:border-emerald-800 shadow-sm' : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-gray-200 dark:border-slate-700 hover:bg-gray-50 dark:hover:bg-slate-700 hover:border-gray-300 dark:hover:border-slate-600'}`} 
                                title={lastSavedTime ? `Last Auto-Saved: ${lastSavedTime}. Click to Open Time Machine.` : "Open Session History"}
                            >
                                <div className="relative">
                                    <Icon name="History" size={18}/>
                                    {lastSavedTime && (
                                        <span className="absolute -top-1 -right-1 flex h-2.5 w-2.5">
                                            {isSaving && <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-red-400 opacity-75"></span>}
                                            <span className={`relative inline-flex rounded-full h-2.5 w-2.5 ${isSaving ? 'bg-red-500' : 'bg-emerald-500'}`}></span>
                                        </span>
                                    )}
                                </div>
                                <span className="hidden xl:inline text-xs font-bold">Recall</span>
                            </button>

                            <button 
                                onClick={(e) => handleNewSession(e)} 
                                className="h-10 w-10 md:w-auto md:px-4 bg-amber-50 dark:bg-amber-950/30 text-amber-600 dark:text-amber-500 border border-amber-200 dark:border-amber-800/50 rounded-xl flex items-center justify-center gap-2 transition-all shadow-sm hover:shadow-amber-500/20 hover:bg-amber-100 dark:hover:bg-amber-900/50 hover:text-amber-700 dark:hover:text-amber-400 duration-300 active:scale-95" 
                                title="Start New Session (Archives current data)"
                            >
                                <Icon name="Session4_FilePlus" size={18}/>
                                <span className="hidden md:inline text-xs font-bold">New</span>
                            </button>
                        </div>
                    </div>

                    <div className="flex-1 overflow-hidden relative p-2 md:p-4">
                        {layoutMode === 'evidence' && (
                            <EvidenceView
                                evidence={evidence}
                                setEvidence={setEvidence}
                                uploadedFiles={uploadedFiles}
                                setUploadedFiles={setUploadedFiles}
                                onOcrProcess={handleOcrUpload}
                                isOcrLoading={isOcrLoading}
                                onAnalyze={handleAnalyze}
                                isReadyForAnalysis={isReadyForAnalysis}
                                isAnalyzeLoading={isAnalyzeLoading}
                                analyzeTooltip={getAnalyzeTooltip()}
                                onExport={(type, lang) => startSmartExport(evidence, type, lang)}
                                evidenceLanguage={evidenceLanguage}
                                setEvidenceLanguage={setEvidenceLanguage}
                                textareaRef={evidenceTextareaRef}
                                tags={evidenceTags} 
                                onAddTag={(newTag) => setEvidenceTags(prev => [...prev, newTag])} 
                                selectedClauses={selectedClauses}
                                // Pass standard info for Matrix
                                standards={allStandards}
                                standardKey={standardKey}
                                matrixData={matrixData}
                                setMatrixData={setMatrixData}
                                // New for Multi-Dept
                                availableDepartments={auditInfo.departments || []}
                                activeDepartment={activeDepartment}
                                setActiveDepartment={setActiveDepartment}
                            />
                        )}
                        {layoutMode === 'findings' && (
                            <FindingsView
                                analysisResult={analysisResult}
                                setAnalysisResult={setAnalysisResult}
                                selectedFindings={selectedFindings}
                                setSelectedFindings={setSelectedFindings}
                                isAnalyzeLoading={isAnalyzeLoading}
                                loadingMessage={loadingMessage}
                                currentAnalyzingClause={currentAnalyzingClause}
                                viewMode={findingsViewMode}
                                setViewMode={setFindingsViewMode}
                                focusedFindingIndex={focusedFindingIndex}
                                setFocusedFindingIndex={setFocusedFindingIndex}
                                onExport={(type, lang) => {
                                    const text = analysisResult?.map(r => `[${r.clauseId}] ${r.status}\nEvidence: ${r.evidence}\nReason: ${r.reason}\nSuggestion: ${r.suggestion}`).join('\n\n') || "";
                                    startSmartExport(text, type, lang);
                                }}
                                notesLanguage={notesLanguage}
                                setNotesLanguage={setNotesLanguage}
                            />
                        )}
                        {layoutMode === 'report' && (
                            <ReportView
                                finalReportText={finalReportText}
                                setFinalReportText={setFinalReportText}
                                isReportLoading={isReportLoading}
                                loadingMessage={loadingMessage}
                                templateFileName={templateFileName}
                                handleTemplateUpload={handleTemplateUpload}
                                handleGenerateReport={handleGenerateReport}
                                isReadyToSynthesize={isReadyToSynthesize}
                                onExport={(type, lang) => startSmartExport(finalReportText || "", type, lang)}
                                exportLanguage={exportLanguage}
                                setExportLanguage={setExportLanguage}
                            />
                        )}
                    </div>
                </div>
            </main>

            <CommandPaletteModal 
                isOpen={isCmdPaletteOpen} 
                onClose={() => setIsCmdPaletteOpen(false)} 
                actions={commandActions} 
                onSelectAction={(action: any) => { action.action(); }} 
            />

            <ProjectInfoModal isOpen={showAboutModal} onClose={() => setShowAboutModal(false)} />

            <ReferenceClauseModal 
                isOpen={referenceClauseState.isOpen} 
                onClose={() => setReferenceClauseState(prev => ({ ...prev, isOpen: false }))}
                clause={referenceClauseState.clause}
                standardName={allStandards[standardKey]?.name || ""}
                fullText={referenceClauseState.fullText}
                isLoading={referenceClauseState.isLoading}
                onInsert={handleInsertReferenceText}
            />

            <RecallModal
                isOpen={showRecallModal}
                onClose={() => setShowRecallModal(false)}
                onRestore={handleRestoreSnapshot}
            />

            <ExportProgressModal 
                exportState={exportState}
                setExportState={setExportState}
                rescueKey={rescueKey}
                setRescueKey={setRescueKey}
                handleResumeExport={handleResumeExport}
                isRescuing={isRescuing}
                onClose={() => setExportState(prev => ({ ...prev, isOpen: false }))} 
                onSkip={handleSkipExportChunk}
            />

            <SettingsModal
                isOpen={showSettingsModal}
                onClose={() => setShowSettingsModal(false)}
                apiKeys={apiKeys}
                newKeyInput={newKeyInput}
                setNewKeyInput={setNewKeyInput}
                isCheckingKey={isCheckingKey}
                handleAddKey={handleAddKey}
                activeKeyId={activeKeyId}
                editingKeyId={editingKeyId}
                editLabelInput={editLabelInput}
                setEditLabelInput={setEditLabelInput}
                handleSaveLabel={handleSaveLabel}
                handleStartEdit={handleStartEdit}
                handleRefreshStatus={handleRefreshStatus}
                handleDeleteKey={handleDeleteKey}
                isAutoCheckEnabled={isAutoCheckEnabled}
                toggleAutoCheck={toggleAutoCheck}
            />

            <AddStandardModal
                isOpen={showAddStandardModal}
                onClose={() => setShowAddStandardModal(false)}
                onAdd={handleAddStandard}
            />
        </div>
    );
}

import React, { useRef, useState, useCallback } from 'react';
import { Icon, SparkleLoader } from '../UI';
import { UploadedFile } from '../../App'; 
import { EvidenceTag, StandardsData, MatrixRow } from '../../types';
import { EvidenceMatrix, EvidenceMatrixHandle } from './EvidenceMatrix'; 
import { fileToBase64 } from '../../utils';
import { generateOcrContent } from '../../services/geminiService';

interface EvidenceViewProps {
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    uploadedFiles: UploadedFile[];
    setUploadedFiles: React.Dispatch<React.SetStateAction<UploadedFile[]>>;
    onOcrProcess: () => void;
    isOcrLoading: boolean;
    onAnalyze: () => void;
    isReadyForAnalysis: boolean;
    isAnalyzeLoading: boolean;
    analyzeTooltip: string;
    onExport: (type: 'evidence', lang: 'en' | 'vi') => void;
    evidenceLanguage: 'en' | 'vi';
    setEvidenceLanguage: (lang: 'en' | 'vi') => void;
    textareaRef: React.RefObject<HTMLTextAreaElement | null>;

    tags?: EvidenceTag[];
    onAddTag?: (tag: EvidenceTag) => void;
    selectedClauses?: string[];

    standards?: StandardsData;
    standardKey?: string;
    matrixData?: Record<string, MatrixRow[]>;
    setMatrixData?: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;

    // NEW FOR MULTI-DEPT
    availableDepartments?: string[];
    activeDepartment?: string;
    setActiveDepartment?: (dept: string) => void;
}

export const EvidenceView: React.FC<EvidenceViewProps> = ({
    evidence, setEvidence, uploadedFiles, setUploadedFiles,
    onOcrProcess, isOcrLoading, onAnalyze, isReadyForAnalysis,
    isAnalyzeLoading, analyzeTooltip, onExport, evidenceLanguage, setEvidenceLanguage,
    textareaRef, tags = [], onAddTag, selectedClauses = [],
    standards, standardKey, matrixData, setMatrixData,
    availableDepartments = [], activeDepartment = "", setActiveDepartment
}) => {
    // --- STATE ---
    const [isDragging, setIsDragging] = useState(false);
    const [isListening, setIsListening] = useState(false); 
    const [viewMode, setViewMode] = useState<'document' | 'matrix'>('document'); 
    const [isMatrixProcessing, setIsMatrixProcessing] = useState(false);
    const [selectionMenu, setSelectionMenu] = useState<{ x: number, y: number, text: string, start: number, end: number } | null>(null);

    // --- REFS ---
    const fileTargetRef = useRef<Record<string, { clauseId: string, rowId: string }>>({});
    const fileInputRef = useRef<HTMLInputElement>(null);
    const recognitionRef = useRef<any>(null);
    const matrixRef = useRef<EvidenceMatrixHandle>(null);

    // --- HELPER: INSERT DEPT MARKER ---
    const insertDeptMarker = () => {
        if (!activeDepartment) return;
        const marker = `\n\n=== 🏢 DEPARTMENT: ${activeDepartment.toUpperCase()} ===\n`;
        if (textareaRef.current) {
            const textarea = textareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newText = evidence.substring(0, start) + marker + evidence.substring(end);
            setEvidence(newText);
            // Move cursor after
            setTimeout(() => {
                textarea.focus();
                textarea.setSelectionRange(start + marker.length, start + marker.length);
            }, 50);
        } else {
            setEvidence(prev => prev + marker);
        }
    };

    // --- HANDLERS: VOICE ---
    const toggleListening = useCallback(() => {
        if (isListening) {
            recognitionRef.current?.stop();
            setIsListening(false);
            return;
        }

        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (!SpeechRecognition) {
            alert("Voice-to-Text is not supported in this browser (Try Chrome/Edge).");
            return;
        }

        // Matrix Mode Safety Check
        if (viewMode === 'matrix' && matrixRef.current && !matrixRef.current.getActiveRow()) {
            alert("Please click inside a Matrix cell first to dictate.");
            return;
        }

        try {
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            // Configurable Language
            recognition.lang = evidenceLanguage === 'vi' ? 'vi-VN' : 'en-US';

            recognition.onstart = () => {
                // Auto-insert marker if needed
                if (viewMode === 'document' && activeDepartment) {
                    insertDeptMarker();
                }
            };

            recognition.onresult = (event: any) => {
                let finalTranscript = '';
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) {
                        finalTranscript += event.results[i][0].transcript;
                    }
                }

                if (finalTranscript) {
                    const cleanText = finalTranscript.trim();
                    if (viewMode === 'matrix' && matrixRef.current) {
                        matrixRef.current.handleExternalDictation(cleanText);
                    } else {
                        setEvidence(prev => prev + (prev ? " " : "") + cleanText);
                    }
                }
            };

            recognition.onerror = (event: any) => {
                console.error("Speech Error", event.error);
                setIsListening(false);
            };

            recognition.onend = () => {
                setIsListening(false);
            };

            recognition.start();
            recognitionRef.current = recognition;
            setIsListening(true);
        } catch (e) {
            console.error("Failed to start recognition", e);
            setIsListening(false);
        }
    }, [isListening, viewMode, evidenceLanguage, setEvidence, activeDepartment]);

    // --- HANDLERS: FILE PROCESSING ---
    const processNewFiles = useCallback((files: File[], targetOverride?: { clauseId: string, rowId: string }) => {
        // Matrix Mode Handling
        if (viewMode === 'matrix') {
            const target = targetOverride || matrixRef.current?.getActiveRow();
            if (!target) {
                alert("Please select a specific cell in the Matrix to attach these files.");
                return;
            }

            const newFiles = files.map(f => {
                const id = Math.random().toString(36).substr(2, 9);
                fileTargetRef.current[id] = target;
                return { id, file: f, status: 'pending' as const };
            });
            setUploadedFiles(prev => [...prev, ...newFiles]);
            return;
        }

        // Document Mode Handling
        const newFiles = files.map(f => ({
            id: Math.random().toString(36).substr(2, 9),
            file: f,
            status: 'pending' as const
        }));
        setUploadedFiles(prev => [...prev, ...newFiles]);
    }, [viewMode, setUploadedFiles]);

    const handleMatrixOcrProcess = useCallback(async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;

        setIsMatrixProcessing(true);

        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));

                let text = "";
                if (fileEntry.file.type.startsWith('image/')) {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await generateOcrContent("Transcribe text.", base64, fileEntry.file.type);
                } else if (fileEntry.file.type === 'application/pdf') {
                     // For pure PDF text, standard OCR prompt works if converted to image or if backend supports it.
                     // Here we assume standard OCR flow
                     // NOTE: In a real app, you might want to use pdf.js locally first.
                     text = "[PDF Content extracted via OCR would go here]"; 
                } else {
                    text = await fileEntry.file.text();
                }

                if (text && matrixRef.current) {
                    const target = fileTargetRef.current[fileEntry.id];
                    if (target) {
                        const header = `[File: ${fileEntry.file.name}]`;
                        matrixRef.current.insertEvidence(target.clauseId, target.rowId, `${header}\n${text}`);

                        setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                        delete fileTargetRef.current[fileEntry.id];
                    } else {
                        throw new Error("Target row lost");
                    }
                } else {
                    throw new Error("No text extracted");
                }
            } catch (error: any) {
                console.error("Matrix OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsMatrixProcessing(false);
    }, [uploadedFiles, setUploadedFiles]);

    // --- HANDLERS: DRAG & DROP & TAGGING ---
    const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); }, []);
    const handleDragLeave = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); }, []);
    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            processNewFiles(Array.from(e.dataTransfer.files));
        }
    }, [processNewFiles]);

    const handleTextSelect = useCallback((e: React.MouseEvent) => {
        if (viewMode === 'matrix' || !textareaRef.current) return;
        const start = textareaRef.current.selectionStart;
        const end = textareaRef.current.selectionEnd;

        if (start !== end) {
            setSelectionMenu({ 
                x: e.clientX, 
                y: e.clientY, 
                text: evidence.substring(start, end), 
                start, 
                end 
            });
        } else {
            setSelectionMenu(null);
        }
    }, [viewMode, evidence]);

    const confirmTag = (clauseId: string) => {
        if (selectionMenu && onAddTag) {
            onAddTag({
                id: `tag_${Date.now()}`,
                clauseId,
                text: selectionMenu.text,
                startIndex: selectionMenu.start,
                endIndex: selectionMenu.end,
                timestamp: Date.now()
            });
            setSelectionMenu(null);
        }
    };

    return (
        <div className="h-full flex flex-col gap-2 md:gap-4 animate-fade-in-up relative">

            {/* VIEW TOGGLE & CONTEXT SWITCHER */}
            <div className="flex flex-col md:flex-row gap-2 justify-between items-center py-2">
                {/* View Switcher */}
                <div className="flex bg-gray-100 dark:bg-slate-950 p-1 rounded-xl shadow-inner border border-gray-200 dark:border-slate-800">
                    <button 
                        onClick={() => setViewMode('document')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${viewMode === 'document' ? 'bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                    >
                        <Icon name="FileText" size={14}/> Document
                    </button>
                    <button 
                        onClick={() => setViewMode('matrix')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${viewMode === 'matrix' ? 'bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                    >
                        <Icon name="LayoutList" size={14}/> Matrix
                    </button>
                </div>

                {/* Context Switcher (Only if Depts defined) */}
                {availableDepartments.length > 0 && setActiveDepartment && (
                    <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/20 px-3 py-1.5 rounded-xl border border-indigo-100 dark:border-indigo-800/50 shadow-sm animate-in fade-in slide-in-from-top-2">
                        <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider flex items-center gap-1">
                            <Icon name="Users" size={12}/> Context:
                        </span>
                        <select 
                            value={activeDepartment}
                            onChange={(e) => setActiveDepartment(e.target.value)}
                            className="bg-transparent text-xs font-bold text-slate-700 dark:text-white outline-none cursor-pointer hover:text-indigo-600"
                        >
                            <option value="">Global / All</option>
                            {availableDepartments.map(d => (
                                <option key={d} value={d}>{d}</option>
                            ))}
                        </select>
                        {activeDepartment && viewMode === 'document' && (
                            <button 
                                onClick={insertDeptMarker}
                                className="ml-2 px-2 py-0.5 bg-white dark:bg-slate-800 rounded text-[9px] font-bold text-indigo-600 dark:text-indigo-400 shadow-sm hover:scale-105 active:scale-95 transition-transform"
                                title="Insert Department Marker into Text"
                            >
                                + Insert Marker
                            </button>
                        )}
                    </div>
                )}
            </div>

            <div className="flex-1 flex flex-col gap-2 md:gap-4 min-h-0 relative">

                {/* FLOATING TAG MENU */}
                {selectionMenu && selectedClauses && selectedClauses.length > 0 && viewMode === 'document' && (
                    <div 
                        className="fixed z-[9999] bg-slate-900/90 backdrop-blur-md text-white p-2.5 rounded-xl shadow-2xl flex flex-col gap-2 animate-in zoom-in-95 duration-200 border border-slate-700/50 ring-1 ring-white/10 max-w-[200px]"
                        style={{ top: selectionMenu.y - 120, left: Math.min(selectionMenu.x - 100, window.innerWidth - 220) }}
                    >
                        <div className="flex justify-between items-center border-b border-slate-700/50 pb-1.5 mb-1">
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-300 flex items-center gap-1">
                                <Icon name="Tag" size={10}/> Tag As:
                            </span>
                            <button onClick={() => setSelectionMenu(null)} className="text-slate-400 hover:text-white bg-white/10 rounded-full p-0.5"><Icon name="X" size={10}/></button>
                        </div>
                        <div className="flex flex-wrap gap-1.5 justify-start max-h-[150px] overflow-y-auto custom-scrollbar">
                            {selectedClauses.map(clauseId => (
                                <button 
                                    key={clauseId}
                                    onClick={() => confirmTag(clauseId)}
                                    className="text-[10px] font-mono font-bold bg-indigo-600 hover:bg-indigo-50 text-white px-2 py-1 rounded-lg transition-all active:scale-95 shadow-sm border border-indigo-500 hover:border-indigo-400"
                                >
                                    {clauseId}
                                </button>
                            ))}
                        </div>
                        <div className="absolute bottom-[-6px] left-1/2 -translate-x-1/2 w-3 h-3 bg-slate-900/90 rotate-45 border-r border-b border-slate-700/50"></div>
                    </div>
                )}

                {/* MAIN CONTENT AREA */}
                <div
                    className={`flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border overflow-hidden flex flex-col relative group transition-all duration-300 dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05),0_4px_6px_-1px_rgba(0,0,0,0.5)] ${isDragging ? 'border-indigo-500 ring-4 ring-indigo-500/20 bg-indigo-50/10' : 'border-gray-100 dark:border-transparent'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                >
                    {isDragging && (
                        <div className="absolute inset-0 bg-indigo-500/10 backdrop-blur-[2px] z-50 flex flex-col items-center justify-center pointer-events-none animate-in fade-in zoom-in-95 duration-200">
                            <div className="p-6 rounded-full bg-white dark:bg-slate-900 shadow-2xl border-4 border-dashed border-indigo-500">
                                <Icon name="UploadCloud" size={48} className="text-indigo-600 animate-bounce" />
                            </div>
                            <h3 className="mt-4 text-xl font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest text-center">Drop Files to Extract<br /><span className="text-sm font-normal normal-case">(Images, PDF, TXT)</span></h3>
                        </div>
                    )}

                    {viewMode === 'document' ? (
                        <textarea
                            ref={textareaRef}
                            className="flex-1 w-full h-full p-4 pb-6 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-medium text-sm leading-relaxed text-justify break-words whitespace-pre-wrap selection:bg-indigo-200 dark:selection:bg-indigo-900/60"
                            placeholder="Paste audit evidence here or use Voice Dictation..."
                            value={evidence}
                            onChange={(e) => setEvidence(e.target.value)}
                            onPaste={(e) => {
                                if (e.clipboardData.files.length > 0) {
                                    e.preventDefault();
                                    processNewFiles(Array.from(e.clipboardData.files));
                                }
                            }}
                            onMouseUp={handleTextSelect} 
                        />
                    ) : (
                        standards && standardKey && standards[standardKey] && matrixData && setMatrixData ? (
                            <div className="flex-1 w-full h-full bg-gray-50/30 dark:bg-slate-950/30 p-2">
                                <EvidenceMatrix 
                                    ref={matrixRef}
                                    standard={standards[standardKey]}
                                    selectedClauses={selectedClauses}
                                    matrixData={matrixData}
                                    setMatrixData={setMatrixData}
                                    onPasteFiles={processNewFiles}
                                />
                            </div>
                        ) : (
                            <div className="flex-1 flex items-center justify-center text-slate-400">
                                Please select a Standard to use Matrix Mode.
                            </div>
                        )
                    )}

                    {/* Floating Tags Indicator */}
                    {tags.length > 0 && viewMode === 'document' && (
                        <div className="absolute bottom-4 right-4 pointer-events-none opacity-60 group-hover:opacity-100 transition-opacity">
                            <div className="bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm border border-indigo-100 dark:border-indigo-900/50 text-indigo-600 dark:text-indigo-300 text-[10px] font-bold px-3 py-1.5 rounded-full shadow-lg flex items-center gap-2">
                                <Icon name="Tag" size={12}/>
                                {tags.length} Evidence Tags
                            </div>
                        </div>
                    )}
                </div>

                {/* UPLOAD QUEUE */}
                {uploadedFiles.length > 0 && (
                    <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-white/5 rounded-2xl animate-in slide-in-from-bottom-5 duration-300 dark:shadow-inner">
                        {viewMode === 'matrix' && (
                            <div className="mb-2 text-[10px] font-bold text-indigo-500 uppercase tracking-widest px-1">
                                Matrix Queue: Files will attach to active cells
                            </div>
                        )}
                        <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                            {uploadedFiles.map((fileEntry) => (
                                <div key={fileEntry.id} className={`relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl shadow-sm border overflow-hidden transition-all duration-300 dark:shadow-lg ${fileEntry.status === 'error' ? 'border-red-500 ring-2 ring-red-500/20' : 'border-gray-100 dark:border-white/5'}`}>
                                    {fileEntry.file.type.startsWith('image/') ? (
                                        <img src={URL.createObjectURL(fileEntry.file)} alt="preview" className={`w-full h-full object-cover transition-opacity ${fileEntry.status === 'processing' ? 'opacity-30' : 'opacity-80 group-hover:opacity-100'}`} />
                                    ) : (
                                        <div className="w-full h-full flex flex-col items-center justify-center bg-indigo-50 dark:bg-indigo-900/20 p-2 text-center">
                                            <Icon name={fileEntry.file.type === 'application/pdf' ? 'FileText' : 'Book'} size={24} className="text-indigo-600 dark:text-indigo-400 mb-1" />
                                            <span className="text-[8px] font-bold text-indigo-700 dark:text-indigo-300 truncate w-full">{fileEntry.file.name}</span>
                                        </div>
                                    )}

                                    {fileEntry.status === 'processing' && (
                                        <div className="absolute inset-0 flex items-center justify-center bg-white/40 dark:bg-black/40">
                                            <Icon name="Loader" className="animate-spin text-indigo-600" size={24} />
                                        </div>
                                    )}
                                    {fileEntry.status === 'success' && (
                                        <div className="absolute top-1 right-1 bg-emerald-500 text-white rounded-full p-0.5 shadow-sm">
                                            <Icon name="CheckThick" size={10} />
                                        </div>
                                    )}
                                    {fileEntry.status === 'error' && (
                                        <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-50/80 dark:bg-red-950/80 p-1 text-center">
                                            <Icon name="AlertCircle" size={20} className="text-red-600" />
                                            <span className="text-[7px] font-black text-red-600 uppercase leading-tight mt-1">{fileEntry.error || 'Err'}</span>
                                        </div>
                                    )}

                                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center z-20">
                                        <button onClick={() => setUploadedFiles(prev => prev.filter(f => f.id !== fileEntry.id))} className="bg-red-500 hover:bg-red-600 text-white rounded-full p-1.5 shadow-lg transform scale-90 hover:scale-110 transition-all duration-200"><Icon name="X" size={14} /></button>
                                    </div>
                                </div>
                            ))}
                            <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center">
                                <button 
                                    onClick={viewMode === 'matrix' ? handleMatrixOcrProcess : onOcrProcess} 
                                    disabled={(isOcrLoading || isMatrixProcessing) || !uploadedFiles.some(f => f.status === 'pending' || f.status === 'error')} 
                                    className="w-full h-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-500/30 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 hover:scale-105 duration-300"
                                >
                                    {(isOcrLoading || isMatrixProcessing) ? <Icon name="Loader" className="animate-spin" size={24} /> : <Icon name="ScanText" size={24} />}
                                    <span className="text-[10px] font-bold">Process</span>
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* ACTION TOOLBAR - VERTICALLY CENTERED */}
            <div className="flex-shrink-0 flex flex-row items-center md:justify-end gap-2 md:gap-3 w-full py-2">
                <div className="flex-none w-[52px] md:w-auto">
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*,application/pdf,text/plain" multiple onChange={(e) => e.target.files && processNewFiles(Array.from(e.target.files))} />
                    <button onClick={() => fileInputRef.current?.click()} className={`w-full h-[52px] md:w-auto md:px-4 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm border whitespace-nowrap ${uploadedFiles.length > 0 ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:border-indigo-500'}`} title={viewMode === 'matrix' ? "Upload to Active Matrix Cell" : "Upload Files"}>
                        <Icon name={uploadedFiles.length > 0 ? "Demo1_MultiFiles" : "Demo8_GridPlus"} size={20} />
                        <span className="hidden md:inline">Upload</span>
                    </button>
                </div>

                <button
                    onClick={toggleListening}
                    className={`flex-none w-[52px] md:w-auto md:px-4 h-[52px] rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm border whitespace-nowrap ${isListening ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 animate-pulse' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:border-indigo-500'}`}
                    title={isListening ? "Click to Stop" : `Start Dictation (${evidenceLanguage.toUpperCase()})`}
                >
                    <Icon name="Mic" size={20} className={isListening ? "animate-pulse" : ""} />
                    <span className="hidden md:inline">
                        {isListening ? `Recording (${evidenceLanguage.toUpperCase()})...` : `Dictate (${evidenceLanguage.toUpperCase()})`}
                    </span>
                </button>

                <button onClick={onAnalyze} disabled={!isReadyForAnalysis} title={analyzeTooltip} className={`flex-1 md:flex-none md:w-auto md:px-6 h-[52px] rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 shadow-lg whitespace-nowrap ${isReadyForAnalysis ? "btn-shrimp text-white active:scale-95" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                    {isAnalyzeLoading ? <SparkleLoader className="text-white" /> : <Icon name="Wand2" size={20} className="hidden md:block" />}
                    <span className="inline text-xs uppercase tracking-wider">Analyze</span>
                </button>

                <button onClick={() => onExport('evidence', evidenceLanguage)} disabled={!evidence || !evidence.trim()} className="flex-none md:w-auto px-3 md:px-4 h-[52px] bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 whitespace-nowrap dark:shadow-md">
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export</span>
                    <div className="lang-pill-container ml-1" title="Select Input/Export Language">
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('en'); }} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('vi'); }} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { useRef, useState, useCallback } from 'react';
import { Icon, SparkleLoader } from '../UI';
import { UploadedFile } from '../../App'; 
import { EvidenceTag, StandardsData, MatrixRow } from '../../types';
import { EvidenceMatrix, EvidenceMatrixHandle } from './EvidenceMatrix'; 
import { fileToBase64 } from '../../utils';
import { generateOcrContent } from '../../services/geminiService';

interface EvidenceViewProps {
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    uploadedFiles: UploadedFile[];
    setUploadedFiles: React.Dispatch<React.SetStateAction<UploadedFile[]>>;
    onOcrProcess: () => void;
    isOcrLoading: boolean;
    onAnalyze: () => void;
    isReadyForAnalysis: boolean;
    isAnalyzeLoading: boolean;
    analyzeTooltip: string;
    onExport: (type: 'evidence', lang: 'en' | 'vi') => void;
    evidenceLanguage: 'en' | 'vi';
    setEvidenceLanguage: (lang: 'en' | 'vi') => void;
    textareaRef: React.RefObject<HTMLTextAreaElement | null>;

    tags?: EvidenceTag[];
    onAddTag?: (tag: EvidenceTag) => void;
    selectedClauses?: string[];

    standards?: StandardsData;
    standardKey?: string;
    matrixData?: Record<string, MatrixRow[]>;
    setMatrixData?: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;

    // NEW FOR MULTI-DEPT
    availableDepartments?: string[];
    activeDepartment?: string;
    setActiveDepartment?: (dept: string) => void;
}

export const EvidenceView: React.FC<EvidenceViewProps> = ({
    evidence, setEvidence, uploadedFiles, setUploadedFiles,
    onOcrProcess, isOcrLoading, onAnalyze, isReadyForAnalysis,
    isAnalyzeLoading, analyzeTooltip, onExport, evidenceLanguage, setEvidenceLanguage,
    textareaRef, tags = [], onAddTag, selectedClauses = [],
    standards, standardKey, matrixData, setMatrixData,
    availableDepartments = [], activeDepartment = "", setActiveDepartment
}) => {
    // --- STATE ---
    const [isDragging, setIsDragging] = useState(false);
    const [isListening, setIsListening] = useState(false); 
    const [viewMode, setViewMode] = useState<'document' | 'matrix'>('document'); 
    const [isMatrixProcessing, setIsMatrixProcessing] = useState(false);
    const [selectionMenu, setSelectionMenu] = useState<{ x: number, y: number, text: string, start: number, end: number } | null>(null);

    // --- REFS ---
    const fileTargetRef = useRef<Record<string, { clauseId: string, rowId: string }>>({});
    const fileInputRef = useRef<HTMLInputElement>(null);
    const recognitionRef = useRef<any>(null);
    const matrixRef = useRef<EvidenceMatrixHandle>(null);

    // --- HELPER: INSERT DEPT MARKER ---
    const insertDeptMarker = () => {
        if (!activeDepartment) return;
        const marker = `\n\n=== 🏢 DEPARTMENT: ${activeDepartment.toUpperCase()} ===\n`;
        if (textareaRef.current) {
            const textarea = textareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newText = evidence.substring(0, start) + marker + evidence.substring(end);
            setEvidence(newText);
            // Move cursor after
            setTimeout(() => {
                textarea.focus();
                textarea.setSelectionRange(start + marker.length, start + marker.length);
            }, 50);
        } else {
            setEvidence(prev => prev + marker);
        }
    };

    // --- HANDLERS: VOICE ---
    const toggleListening = useCallback(() => {
        if (isListening) {
            recognitionRef.current?.stop();
            setIsListening(false);
            return;
        }

        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (!SpeechRecognition) {
            alert("Voice-to-Text is not supported in this browser (Try Chrome/Edge).");
            return;
        }

        // Matrix Mode Safety Check
        if (viewMode === 'matrix' && matrixRef.current && !matrixRef.current.getActiveRow()) {
            alert("Please click inside a Matrix cell first to dictate.");
            return;
        }

        try {
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            // Configurable Language
            recognition.lang = evidenceLanguage === 'vi' ? 'vi-VN' : 'en-US';

            recognition.onstart = () => {
                // Auto-insert marker if needed
                if (viewMode === 'document' && activeDepartment) {
                    insertDeptMarker();
                }
            };

            recognition.onresult = (event: any) => {
                let finalTranscript = '';
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) {
                        finalTranscript += event.results[i][0].transcript;
                    }
                }

                if (finalTranscript) {
                    const cleanText = finalTranscript.trim();
                    if (viewMode === 'matrix' && matrixRef.current) {
                        matrixRef.current.handleExternalDictation(cleanText);
                    } else {
                        setEvidence(prev => prev + (prev ? " " : "") + cleanText);
                    }
                }
            };

            recognition.onerror = (event: any) => {
                console.error("Speech Error", event.error);
                setIsListening(false);
            };

            recognition.onend = () => {
                setIsListening(false);
            };

            recognition.start();
            recognitionRef.current = recognition;
            setIsListening(true);
        } catch (e) {
            console.error("Failed to start recognition", e);
            setIsListening(false);
        }
    }, [isListening, viewMode, evidenceLanguage, setEvidence, activeDepartment]);

    // --- HANDLERS: FILE PROCESSING ---
    const processNewFiles = useCallback((files: File[], targetOverride?: { clauseId: string, rowId: string }) => {
        // Matrix Mode Handling
        if (viewMode === 'matrix') {
            const target = targetOverride || matrixRef.current?.getActiveRow();
            if (!target) {
                alert("Please select a specific cell in the Matrix to attach these files.");
                return;
            }

            const newFiles = files.map(f => {
                const id = Math.random().toString(36).substr(2, 9);
                fileTargetRef.current[id] = target;
                return { id, file: f, status: 'pending' as const };
            });
            setUploadedFiles(prev => [...prev, ...newFiles]);
            return;
        }

        // Document Mode Handling
        const newFiles = files.map(f => ({
            id: Math.random().toString(36).substr(2, 9),
            file: f,
            status: 'pending' as const
        }));
        setUploadedFiles(prev => [...prev, ...newFiles]);
    }, [viewMode, setUploadedFiles]);

    const handleMatrixOcrProcess = useCallback(async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;

        setIsMatrixProcessing(true);

        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));

                let text = "";
                if (fileEntry.file.type.startsWith('image/')) {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await generateOcrContent("Transcribe text.", base64, fileEntry.file.type);
                } else if (fileEntry.file.type === 'application/pdf') {
                     // For pure PDF text, standard OCR prompt works if converted to image or if backend supports it.
                     // Here we assume standard OCR flow
                     // NOTE: In a real app, you might want to use pdf.js locally first.
                     text = "[PDF Content extracted via OCR would go here]"; 
                } else {
                    text = await fileEntry.file.text();
                }

                if (text && matrixRef.current) {
                    const target = fileTargetRef.current[fileEntry.id];
                    if (target) {
                        const header = `[File: ${fileEntry.file.name}]`;
                        matrixRef.current.insertEvidence(target.clauseId, target.rowId, `${header}\n${text}`);

                        setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                        delete fileTargetRef.current[fileEntry.id];
                    } else {
                        throw new Error("Target row lost");
                    }
                } else {
                    throw new Error("No text extracted");
                }
            } catch (error: any) {
                console.error("Matrix OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsMatrixProcessing(false);
    }, [uploadedFiles, setUploadedFiles]);

    // --- HANDLERS: DRAG & DROP & TAGGING ---
    const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); }, []);
    const handleDragLeave = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); }, []);
    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            processNewFiles(Array.from(e.dataTransfer.files));
        }
    }, [processNewFiles]);

    const handleTextSelect = useCallback((e: React.MouseEvent) => {
        if (viewMode === 'matrix' || !textareaRef.current) return;
        const start = textareaRef.current.selectionStart;
        const end = textareaRef.current.selectionEnd;

        if (start !== end) {
            setSelectionMenu({ 
                x: e.clientX, 
                y: e.clientY, 
                text: evidence.substring(start, end), 
                start, 
                end 
            });
        } else {
            setSelectionMenu(null);
        }
    }, [viewMode, evidence]);

    const confirmTag = (clauseId: string) => {
        if (selectionMenu && onAddTag) {
            onAddTag({
                id: `tag_${Date.now()}`,
                clauseId,
                text: selectionMenu.text,
                startIndex: selectionMenu.start,
                endIndex: selectionMenu.end,
                timestamp: Date.now()
            });
            setSelectionMenu(null);
        }
    };

    return (
        <div className="h-full flex flex-col gap-2 md:gap-4 animate-fade-in-up relative">

            {/* VIEW TOGGLE & CONTEXT SWITCHER */}
            <div className="flex flex-col md:flex-row gap-2 justify-between items-center py-2">
                {/* View Switcher */}
                <div className="flex bg-gray-100 dark:bg-slate-950 p-1 rounded-xl shadow-inner border border-gray-200 dark:border-slate-800">
                    <button 
                        onClick={() => setViewMode('document')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${viewMode === 'document' ? 'bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                    >
                        <Icon name="FileText" size={14}/> Document
                    </button>
                    <button 
                        onClick={() => setViewMode('matrix')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${viewMode === 'matrix' ? 'bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                    >
                        <Icon name="LayoutList" size={14}/> Matrix
                    </button>
                </div>

                {/* Context Switcher (Only if Depts defined) */}
                {availableDepartments.length > 0 && setActiveDepartment && (
                    <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/20 px-3 py-1.5 rounded-xl border border-indigo-100 dark:border-indigo-800/50 shadow-sm animate-in fade-in slide-in-from-top-2">
                        <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider flex items-center gap-1">
                            <Icon name="Users" size={12}/> Context:
                        </span>
                        <select 
                            value={activeDepartment}
                            onChange={(e) => setActiveDepartment(e.target.value)}
                            className="bg-transparent text-xs font-bold text-slate-700 dark:text-white outline-none cursor-pointer hover:text-indigo-600 focus:ring-2 focus:ring-indigo-500/20 rounded"
                        >
                            {/* FIX: Explicit styling for options to ensure contrast in all browsers/modes */}
                            <option value="" className="text-slate-900 bg-white dark:bg-slate-800 dark:text-white">Global / All</option>
                            {availableDepartments.map(d => (
                                <option key={d} value={d} className="text-slate-900 bg-white dark:bg-slate-800 dark:text-white">{d}</option>
                            ))}
                        </select>
                        {activeDepartment && viewMode === 'document' && (
                            <button 
                                onClick={insertDeptMarker}
                                className="ml-2 px-2 py-0.5 bg-white dark:bg-slate-800 rounded text-[9px] font-bold text-indigo-600 dark:text-indigo-400 shadow-sm hover:scale-105 active:scale-95 transition-transform"
                                title="Insert Department Marker into Text"
                            >
                                + Insert Marker
                            </button>
                        )}
                    </div>
                )}
            </div>

            <div className="flex-1 flex flex-col gap-2 md:gap-4 min-h-0 relative">

                {/* FLOATING TAG MENU */}
                {selectionMenu && selectedClauses && selectedClauses.length > 0 && viewMode === 'document' && (
                    <div 
                        className="fixed z-[9999] bg-slate-900/90 backdrop-blur-md text-white p-2.5 rounded-xl shadow-2xl flex flex-col gap-2 animate-in zoom-in-95 duration-200 border border-slate-700/50 ring-1 ring-white/10 max-w-[200px]"
                        style={{ top: selectionMenu.y - 120, left: Math.min(selectionMenu.x - 100, window.innerWidth - 220) }}
                    >
                        <div className="flex justify-between items-center border-b border-slate-700/50 pb-1.5 mb-1">
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-300 flex items-center gap-1">
                                <Icon name="Tag" size={10}/> Tag As:
                            </span>
                            <button onClick={() => setSelectionMenu(null)} className="text-slate-400 hover:text-white bg-white/10 rounded-full p-0.5"><Icon name="X" size={10}/></button>
                        </div>
                        <div className="flex flex-wrap gap-1.5 justify-start max-h-[150px] overflow-y-auto custom-scrollbar">
                            {selectedClauses.map(clauseId => (
                                <button 
                                    key={clauseId}
                                    onClick={() => confirmTag(clauseId)}
                                    className="text-[10px] font-mono font-bold bg-indigo-600 hover:bg-indigo-50 text-white px-2 py-1 rounded-lg transition-all active:scale-95 shadow-sm border border-indigo-500 hover:border-indigo-400"
                                >
                                    {clauseId}
                                </button>
                            ))}
                        </div>
                        <div className="absolute bottom-[-6px] left-1/2 -translate-x-1/2 w-3 h-3 bg-slate-900/90 rotate-45 border-r border-b border-slate-700/50"></div>
                    </div>
                )}

                {/* MAIN CONTENT AREA */}
                <div
                    className={`flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border overflow-hidden flex flex-col relative group transition-all duration-300 dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05),0_4px_6px_-1px_rgba(0,0,0,0.5)] ${isDragging ? 'border-indigo-500 ring-4 ring-indigo-500/20 bg-indigo-50/10' : 'border-gray-100 dark:border-transparent'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                >
                    {isDragging && (
                        <div className="absolute inset-0 bg-indigo-500/10 backdrop-blur-[2px] z-50 flex flex-col items-center justify-center pointer-events-none animate-in fade-in zoom-in-95 duration-200">
                            <div className="p-6 rounded-full bg-white dark:bg-slate-900 shadow-2xl border-4 border-dashed border-indigo-500">
                                <Icon name="UploadCloud" size={48} className="text-indigo-600 animate-bounce" />
                            </div>
                            <h3 className="mt-4 text-xl font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest text-center">Drop Files to Extract<br /><span className="text-sm font-normal normal-case">(Images, PDF, TXT)</span></h3>
                        </div>
                    )}

                    {viewMode === 'document' ? (
                        <textarea
                            ref={textareaRef}
                            className="flex-1 w-full h-full p-4 pb-6 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-medium text-sm leading-relaxed text-justify break-words whitespace-pre-wrap selection:bg-indigo-200 dark:selection:bg-indigo-900/60"
                            placeholder="Paste audit evidence here or use Voice Dictation..."
                            value={evidence}
                            onChange={(e) => setEvidence(e.target.value)}
                            onPaste={(e) => {
                                if (e.clipboardData.files.length > 0) {
                                    e.preventDefault();
                                    processNewFiles(Array.from(e.clipboardData.files));
                                }
                            }}
                            onMouseUp={handleTextSelect} 
                        />
                    ) : (
                        standards && standardKey && standards[standardKey] && matrixData && setMatrixData ? (
                            <div className="flex-1 w-full h-full bg-gray-50/30 dark:bg-slate-950/30 p-2">
                                <EvidenceMatrix 
                                    ref={matrixRef}
                                    standard={standards[standardKey]}
                                    selectedClauses={selectedClauses}
                                    matrixData={matrixData}
                                    setMatrixData={setMatrixData}
                                    onPasteFiles={processNewFiles}
                                    activeDepartment={activeDepartment} // PASS THE PROP
                                />
                            </div>
                        ) : (
                            <div className="flex-1 flex items-center justify-center text-slate-400">
                                Please select a Standard to use Matrix Mode.
                            </div>
                        )
                    )}

                    {/* Floating Tags Indicator */}
                    {tags.length > 0 && viewMode === 'document' && (
                        <div className="absolute bottom-4 right-4 pointer-events-none opacity-60 group-hover:opacity-100 transition-opacity">
                            <div className="bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm border border-indigo-100 dark:border-indigo-900/50 text-indigo-600 dark:text-indigo-300 text-[10px] font-bold px-3 py-1.5 rounded-full shadow-lg flex items-center gap-2">
                                <Icon name="Tag" size={12}/>
                                {tags.length} Evidence Tags
                            </div>
                        </div>
                    )}
                </div>

                {/* UPLOAD QUEUE */}
                {uploadedFiles.length > 0 && (
                    <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-white/5 rounded-2xl animate-in slide-in-from-bottom-5 duration-300 dark:shadow-inner">
                        {viewMode === 'matrix' && (
                            <div className="mb-2 text-[10px] font-bold text-indigo-500 uppercase tracking-widest px-1">
                                Matrix Queue: Files will attach to active cells
                            </div>
                        )}
                        <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                            {uploadedFiles.map((fileEntry) => (
                                <div key={fileEntry.id} className={`relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl shadow-sm border overflow-hidden transition-all duration-300 dark:shadow-lg ${fileEntry.status === 'error' ? 'border-red-500 ring-2 ring-red-500/20' : 'border-gray-100 dark:border-white/5'}`}>
                                    {fileEntry.file.type.startsWith('image/') ? (
                                        <img src={URL.createObjectURL(fileEntry.file)} alt="preview" className={`w-full h-full object-cover transition-opacity ${fileEntry.status === 'processing' ? 'opacity-30' : 'opacity-80 group-hover:opacity-100'}`} />
                                    ) : (
                                        <div className="w-full h-full flex flex-col items-center justify-center bg-indigo-50 dark:bg-indigo-900/20 p-2 text-center">
                                            <Icon name={fileEntry.file.type === 'application/pdf' ? 'FileText' : 'Book'} size={24} className="text-indigo-600 dark:text-indigo-400 mb-1" />
                                            <span className="text-[8px] font-bold text-indigo-700 dark:text-indigo-300 truncate w-full">{fileEntry.file.name}</span>
                                        </div>
                                    )}

                                    {fileEntry.status === 'processing' && (
                                        <div className="absolute inset-0 flex items-center justify-center bg-white/40 dark:bg-black/40">
                                            <Icon name="Loader" className="animate-spin text-indigo-600" size={24} />
                                        </div>
                                    )}
                                    {fileEntry.status === 'success' && (
                                        <div className="absolute top-1 right-1 bg-emerald-500 text-white rounded-full p-0.5 shadow-sm">
                                            <Icon name="CheckThick" size={10} />
                                        </div>
                                    )}
                                    {fileEntry.status === 'error' && (
                                        <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-50/80 dark:bg-red-950/80 p-1 text-center">
                                            <Icon name="AlertCircle" size={20} className="text-red-600" />
                                            <span className="text-[7px] font-black text-red-600 uppercase leading-tight mt-1">{fileEntry.error || 'Err'}</span>
                                        </div>
                                    )}

                                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center z-20">
                                        <button onClick={() => setUploadedFiles(prev => prev.filter(f => f.id !== fileEntry.id))} className="bg-red-500 hover:bg-red-600 text-white rounded-full p-1.5 shadow-lg transform scale-90 hover:scale-110 transition-all duration-200"><Icon name="X" size={14} /></button>
                                    </div>
                                </div>
                            ))}
                            <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center">
                                <button 
                                    onClick={viewMode === 'matrix' ? handleMatrixOcrProcess : onOcrProcess} 
                                    disabled={(isOcrLoading || isMatrixProcessing) || !uploadedFiles.some(f => f.status === 'pending' || f.status === 'error')} 
                                    className="w-full h-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-500/30 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 hover:scale-105 duration-300"
                                >
                                    {(isOcrLoading || isMatrixProcessing) ? <Icon name="Loader" className="animate-spin" size={24} /> : <Icon name="ScanText" size={24} />}
                                    <span className="text-[10px] font-bold">Process</span>
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* ACTION TOOLBAR - VERTICALLY CENTERED */}
            <div className="flex-shrink-0 flex flex-row items-center md:justify-end gap-2 md:gap-3 w-full py-2">
                <div className="flex-none w-[52px] md:w-auto">
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*,application/pdf,text/plain" multiple onChange={(e) => e.target.files && processNewFiles(Array.from(e.target.files))} />
                    <button onClick={() => fileInputRef.current?.click()} className={`w-full h-[52px] md:w-auto md:px-4 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm border whitespace-nowrap ${uploadedFiles.length > 0 ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:border-indigo-500'}`} title={viewMode === 'matrix' ? "Upload to Active Matrix Cell" : "Upload Files"}>
                        <Icon name={uploadedFiles.length > 0 ? "Demo1_MultiFiles" : "Demo8_GridPlus"} size={20} />
                        <span className="hidden md:inline">Upload</span>
                    </button>
                </div>

                <button
                    onClick={toggleListening}
                    className={`flex-none w-[52px] md:w-auto md:px-4 h-[52px] rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm border whitespace-nowrap ${isListening ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 animate-pulse' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:border-indigo-500'}`}
                    title={isListening ? "Click to Stop" : `Start Dictation (${evidenceLanguage.toUpperCase()})`}
                >
                    <Icon name="Mic" size={20} className={isListening ? "animate-pulse" : ""} />
                    <span className="hidden md:inline">
                        {isListening ? `Recording (${evidenceLanguage.toUpperCase()})...` : `Dictate (${evidenceLanguage.toUpperCase()})`}
                    </span>
                </button>

                <button onClick={onAnalyze} disabled={!isReadyForAnalysis} title={analyzeTooltip} className={`flex-1 md:flex-none md:w-auto md:px-6 h-[52px] rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 shadow-lg whitespace-nowrap ${isReadyForAnalysis ? "btn-shrimp text-white active:scale-95" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                    {isAnalyzeLoading ? <SparkleLoader className="text-white" /> : <Icon name="Wand2" size={20} className="hidden md:block" />}
                    <span className="inline text-xs uppercase tracking-wider">Analyze</span>
                </button>

                <button onClick={() => onExport('evidence', evidenceLanguage)} disabled={!evidence || !evidence.trim()} className="flex-none md:w-auto px-3 md:px-4 h-[52px] bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 whitespace-nowrap dark:shadow-md">
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export</span>
                    <div className="lang-pill-container ml-1" title="Select Input/Export Language">
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('en'); }} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('vi'); }} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { useEffect, useState, useMemo, useImperativeHandle, forwardRef, useCallback, useRef } from 'react';
import { Icon } from '../UI';
import { Clause, Standard, MatrixRow } from '../../types';
import { copyToClipboard, serializeMatrixData } from '../../utils';

// --- TYPES ---
export interface EvidenceMatrixHandle {
    insertEvidence: (clauseId: string, rowId: string, text: string) => void;
    handleExternalDictation: (text: string) => void;
    getActiveRow: () => { clauseId: string, rowId: string } | null;
}

interface EvidenceMatrixProps {
    standard: Standard;
    selectedClauses: string[];
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    onPasteFiles?: (files: File[], target: { clauseId: string, rowId: string }) => void;
    activeDepartment?: string; // New Prop for Context
}

// --- SUB-COMPONENT: MATRIX ROW (MEMOIZED FOR PERFORMANCE) ---
interface MatrixRowItemProps {
    row: MatrixRow;
    clauseId: string;
    isActive: boolean;
    isProcessing: boolean;
    splitRatio: number; 
    activeDepartment?: string; // Passed down
    onInputChange: (clauseId: string, rowId: string, value: string) => void;
    onFocus: (clauseId: string, rowId: string) => void;
    onPaste: (e: React.ClipboardEvent, clauseId: string, rowId: string) => void;
    onStamp: (clauseId: string, rowId: string, dept: string) => void; // New Handler
}

const MatrixRowItem = React.memo(({ row, clauseId, isActive, isProcessing, splitRatio, activeDepartment, onInputChange, onFocus, onPaste, onStamp }: MatrixRowItemProps) => {
    return (
        <div 
            className="grid gap-4 items-start p-3 hover:bg-gray-50 dark:hover:bg-slate-800/30 rounded-lg transition-colors group relative border border-transparent hover:border-gray-100 dark:hover:border-slate-800"
            style={{ gridTemplateColumns: `${splitRatio}% minmax(0, 1fr)` }}
        >
            <div className="text-[11px] text-slate-600 dark:text-slate-300 font-medium leading-relaxed pt-2 select-none break-words">
                {row.requirement}
            </div>

            <div className="relative min-w-0 group/input">
                {/* Visual Cue for Context: Colored Border if Active Dept + Focused */}
                <textarea
                    rows={3}
                    placeholder={isActive && activeDepartment ? `Type evidence for ${activeDepartment}...` : "Type evidence or paste files here..."}
                    className={`w-full bg-gray-50 dark:bg-slate-950 border rounded-lg p-2 text-xs text-slate-800 dark:text-white outline-none transition-all resize-y min-h-[70px] shadow-sm 
                        ${isProcessing ? 'opacity-50 pointer-events-none' : ''} 
                        ${isActive 
                            ? (activeDepartment ? 'border-indigo-500 ring-2 ring-indigo-500/20 bg-white dark:bg-slate-900' : 'border-indigo-500 ring-2 ring-indigo-500/10 bg-white dark:bg-slate-900')
                            : 'border-gray-200 dark:border-slate-700 focus:border-indigo-400 focus:ring-2 focus:ring-indigo-500/10'
                        }`}
                    value={row.evidenceInput}
                    onChange={(e) => onInputChange(clauseId, row.id, e.target.value)}
                    onFocus={() => onFocus(clauseId, row.id)}
                    onPaste={(e) => onPaste(e, clauseId, row.id)}
                />

                {/* COMPREHENSIVE SOLUTION: CONTEXT STAMP BUTTON */}
                {isActive && activeDepartment && (
                    <div className="absolute top-1.5 right-2 z-20 animate-in fade-in zoom-in duration-200">
                        <button
                            onClick={(e) => { e.preventDefault(); e.stopPropagation(); onStamp(clauseId, row.id, activeDepartment); }}
                            className="flex items-center gap-1 bg-indigo-600 hover:bg-indigo-700 text-white text-[9px] font-bold px-2 py-1 rounded-full shadow-md transition-transform active:scale-95 border border-indigo-400"
                            title={`Click to stamp [${activeDepartment}] header`}
                        >
                            <Icon name="Tag" size={10} />
                            <span>Add {activeDepartment} Entry</span>
                        </button>
                    </div>
                )}

                {/* Status Indicators (Only show if not active/typing to avoid clutter) */}
                {!isActive && row.status === 'supplied' && !isProcessing && (
                    <div className="absolute top-2 right-2 pointer-events-none transition-opacity duration-300">
                        <div className="bg-emerald-500/10 p-0.5 rounded-full">
                            <Icon name="CheckThick" size={10} className="text-emerald-600"/>
                        </div>
                    </div>
                )}

                {/* Processing Indicator */}
                {isProcessing && (
                    <div className="absolute bottom-2 right-2 flex items-center gap-2 px-2 py-1 bg-white dark:bg-slate-800 rounded-md shadow-sm border border-indigo-100 dark:border-slate-600 z-10 animate-in fade-in zoom-in">
                        <Icon name="Loader" className="animate-spin text-indigo-500" size={12}/>
                        <span className="text-[9px] font-bold text-indigo-500">Processing...</span>
                    </div>
                )}
            </div>
        </div>
    );
}, (prev, next) => {
    return (
        prev.row.evidenceInput === next.row.evidenceInput &&
        prev.row.status === next.row.status &&
        prev.isActive === next.isActive &&
        prev.isProcessing === next.isProcessing &&
        prev.splitRatio === next.splitRatio &&
        prev.activeDepartment === next.activeDepartment // Check context change
    );
});

// --- MAIN COMPONENT ---
export const EvidenceMatrix = forwardRef<EvidenceMatrixHandle, EvidenceMatrixProps>(({
    standard, selectedClauses, matrixData, setMatrixData, onPasteFiles, activeDepartment
}, ref) => {
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);

    // Resize State
    const [splitRatio, setSplitRatio] = useState(40); // Initial 40% for Requirement
    const [isResizing, setIsResizing] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    // Track focused row
    const [activeRow, setActiveRow] = useState<{ clauseId: string, rowId: string } | null>(null);
    const [processingRowId, setProcessingRowId] = useState<string | null>(null);

    // 1. Flatten Clauses (Memoized)
    const flatClauses = useMemo(() => {
        const all: Clause[] = [];
        const traverse = (list: Clause[]) => {
            list.forEach(c => {
                all.push(c);
                if(c.subClauses) traverse(c.subClauses);
            });
        };
        standard.groups.forEach(g => traverse(g.clauses));
        return all;
    }, [standard]);

    // 2. Initialize Matrix State (Effect)
    useEffect(() => {
        setMatrixData(currentMatrix => {
            const newMatrix = { ...currentMatrix };
            let updated = false;

            selectedClauses.forEach(clauseId => {
                if (!newMatrix[clauseId]) {
                    const clause = flatClauses.find(c => c.id === clauseId);
                    if (clause) {
                        // Intelligent splitting of description into requirements
                        const desc = clause.description || "";
                        const reqs = desc.length > 60 
                            ? desc.split(/(?:\. |\n)/).filter(s => s.trim().length > 5) 
                            : [desc];

                        newMatrix[clauseId] = reqs.map((req, idx) => ({
                            id: `${clauseId}_req_${idx}`,
                            requirement: req.trim(),
                            evidenceInput: "",
                            status: 'pending'
                        }));
                        updated = true;
                    }
                }
            });

            if (updated) {
                // Auto-expand first clause if nothing expanded
                if(selectedClauses.length > 0 && expandedClauses.length === 0) {
                    setExpandedClauses([selectedClauses[0]]);
                }
                return newMatrix;
            }
            return currentMatrix;
        });
    }, [selectedClauses, flatClauses, setMatrixData]);

    // --- RESIZE HANDLERS ---
    const startResizing = useCallback((e: React.MouseEvent) => {
        e.preventDefault();
        setIsResizing(true);
        document.body.style.cursor = 'col-resize';
        document.body.style.userSelect = 'none';

        const handleMouseMove = (moveEvent: MouseEvent) => {
            if (containerRef.current) {
                const rect = containerRef.current.getBoundingClientRect();
                const relativeX = moveEvent.clientX - rect.left;
                const percentage = (relativeX / rect.width) * 100;
                // Clamp between 20% and 80%
                setSplitRatio(Math.min(80, Math.max(20, percentage)));
            }
        };

        const handleMouseUp = () => {
            setIsResizing(false);
            document.body.style.cursor = '';
            document.body.style.userSelect = '';
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    }, []);

    // --- INPUT HANDLERS (Memoized) ---

    const updateRowData = useCallback((clauseId: string, rowId: string, textToAppend: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => {
                if (row.id === rowId) {
                    const currentText = row.evidenceInput || "";
                    const separator = currentText && textToAppend ? "\n" : "";
                    const newText = currentText + separator + textToAppend;
                    return { ...row, evidenceInput: newText, status: newText.trim() ? 'supplied' : 'pending' };
                }
                return row;
            })
        }));
    }, [setMatrixData]);

    const handleInputChange = useCallback((clauseId: string, rowId: string, value: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => 
                row.id === rowId 
                ? { ...row, evidenceInput: value, status: value.trim() ? 'supplied' : 'pending' } 
                : row
            )
        }));
    }, [setMatrixData]);

    const handlePaste = useCallback((e: React.ClipboardEvent, clauseId: string, rowId: string) => {
        const items = e.clipboardData.items;
        const files: File[] = [];

        // Context-Aware Paste: If dept is active, prepend label
        // We can't easily intercept the text paste here without preventing default,
        // so we handle Files here, and text paste is handled naturally by onChange/textarea
        // BUT for files, we can update the inserted text reference.

        for (let i = 0; i < items.length; i++) {
            if (items[i].kind === 'file') {
                const f = items[i].getAsFile();
                if (f) files.push(f);
            }
        }

        if (files.length > 0) {
            e.preventDefault();
            if (onPasteFiles) {
                // Prepend Context info if available
                if (activeDepartment) {
                    updateRowData(clauseId, rowId, `\n[Dept: ${activeDepartment}] Attaching files...`);
                }
                onPasteFiles(files, { clauseId, rowId });
            }
        }
    }, [onPasteFiles, activeDepartment, updateRowData]);

    const handleFocus = useCallback((clauseId: string, rowId: string) => {
        setActiveRow({ clauseId, rowId });
    }, []);

    // NEW: Handle Stamp Click
    const handleStamp = useCallback((clauseId: string, rowId: string, dept: string) => {
        const stamp = `\n=== 🏢 ${dept.toUpperCase()} ===\n`;
        updateRowData(clauseId, rowId, stamp);
    }, [updateRowData]);

    // --- EXPOSED API ---
    useImperativeHandle(ref, () => ({
        insertEvidence: (clauseId, rowId, text) => {
            // Context prefix for externally inserted evidence (like files)
            const prefix = activeDepartment ? `[${activeDepartment}] ` : "";
            updateRowData(clauseId, rowId, prefix + text);
        },
        handleExternalDictation: (text: string) => {
            if (activeRow) {
                const prefix = activeDepartment ? `[${activeDepartment}] ` : "";
                updateRowData(activeRow.clauseId, activeRow.rowId, prefix + text);
            }
        },
        getActiveRow: () => activeRow
    }));

    // --- UI ACTIONS ---
    const handleCopyMatrixToClipboard = () => {
        const text = serializeMatrixData(matrixData, selectedClauses);
        if(text) {
            copyToClipboard(text);
            alert("Matrix data copied to clipboard as Table!"); 
        } else {
            alert("Matrix is empty.");
        }
    };

    const toggleExpand = (id: string) => {
        setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    };

    // --- RENDER ---
    if (selectedClauses.length === 0) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/50 dark:bg-slate-900/50 rounded-3xl border border-dashed border-gray-200 dark:border-slate-800">
                <Icon name="LayoutList" size={48} className="mb-4 opacity-50"/>
                <p className="text-sm font-medium">Select clauses from the sidebar to start mapping evidence.</p>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col relative animate-fade-in-up" ref={containerRef}>
            <div className="flex-shrink-0 flex justify-between items-center mb-2 px-1">
                 {/* Visual indicator for matrix mode context */}
                 {activeDepartment && (
                     <div className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/20 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800 animate-in slide-in-from-left-2">
                         Active Context: {activeDepartment}
                     </div>
                 )}

                 <button 
                    onClick={handleCopyMatrixToClipboard}
                    className="ml-auto text-[10px] font-bold text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 flex items-center gap-1 bg-white dark:bg-slate-800 px-2 py-1 rounded shadow-sm border border-gray-100 dark:border-slate-700 hover:border-indigo-200 transition-colors"
                    title="Export to Clipboard: Copies current data as a structured Text Table for Excel/Word."
                 >
                    <Icon name="Copy" size={12}/> Copy Matrix Table
                 </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 p-1 pb-10">
                {selectedClauses.map(clauseId => {
                    const clause = flatClauses.find(c => c.id === clauseId);
                    const rows = matrixData[clauseId] || [];
                    const isExpanded = expandedClauses.includes(clauseId);
                    if (!clause) return null;

                    const filledCount = rows.filter(r => r.status === 'supplied').length;
                    const progress = Math.round((filledCount / (rows.length || 1)) * 100);

                    return (
                        <div key={clauseId} className="bg-white dark:bg-slate-900 rounded-xl border border-gray-200 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300">
                            {/* Header */}
                            <div 
                                className="flex items-center justify-between p-3 bg-gray-50/80 dark:bg-slate-800/50 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors select-none"
                                onClick={() => toggleExpand(clauseId)}
                            >
                                <div className="flex items-center gap-3">
                                    <span className="text-xs font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800/50">
                                        {clause.code}
                                    </span>
                                    <h4 className="text-xs font-bold text-slate-700 dark:text-slate-200">{clause.title}</h4>
                                </div>
                                <div className="flex items-center gap-3">
                                    <div className="w-16 h-1.5 bg-gray-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                        <div 
                                            className={`h-full rounded-full transition-all duration-500 ease-out ${progress === 100 ? 'bg-emerald-500' : 'bg-indigo-500'}`} 
                                            style={{ width: `${progress}%` }}
                                        />
                                    </div>
                                    <Icon name={isExpanded ? "ChevronUp" : "ChevronDown"} size={14} className="text-slate-400"/>
                                </div>
                            </div>

                            {/* Body */}
                            {isExpanded && (
                                <div className="p-3 border-t border-gray-100 dark:border-slate-800 animate-accordion-down">
                                    {/* Resizable Header */}
                                    <div 
                                        className="grid gap-4 mb-2 px-3 relative"
                                        style={{ gridTemplateColumns: `${splitRatio}% minmax(0, 1fr)` }}
                                    >
                                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider truncate">Requirement Breakdown</span>
                                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider truncate">Verified Evidence</span>

                                        {/* Resize Handle */}
                                        <div 
                                            className="absolute top-0 bottom-0 w-4 cursor-col-resize flex justify-center group z-10 hover:z-20"
                                            style={{ left: `calc(${splitRatio}% + 0.5rem - 8px)` }} // Center over the gap (gap-4 is 1rem)
                                            onMouseDown={startResizing}
                                            onClick={(e) => e.stopPropagation()}
                                        >
                                            <div className={`w-1 h-full rounded-full transition-colors duration-200 ${isResizing ? 'bg-indigo-500' : 'bg-transparent group-hover:bg-indigo-200 dark:group-hover:bg-indigo-800'}`}></div>
                                        </div>
                                    </div>

                                    <div className="space-y-1">
                                        {rows.map((row) => (
                                            <MatrixRowItem
                                                key={row.id}
                                                row={row}
                                                clauseId={clauseId}
                                                isActive={activeRow?.rowId === row.id}
                                                isProcessing={processingRowId === row.id}
                                                splitRatio={splitRatio}
                                                activeDepartment={activeDepartment} // PASS CONTEXT
                                                onInputChange={handleInputChange}
                                                onFocus={handleFocus}
                                                onPaste={handlePaste}
                                                onStamp={handleStamp} // PASS STAMP HANDLER
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
});

import React, { useRef, useState, useCallback } from 'react';
import { Icon, SparkleLoader } from '../UI';
import { UploadedFile } from '../../App'; 
import { EvidenceTag, StandardsData, MatrixRow } from '../../types';
import { EvidenceMatrix, EvidenceMatrixHandle } from './EvidenceMatrix'; 
import { fileToBase64 } from '../../utils';
import { generateOcrContent } from '../../services/geminiService';

interface EvidenceViewProps {
    evidence: string;
    setEvidence: React.Dispatch<React.SetStateAction<string>>;
    uploadedFiles: UploadedFile[];
    setUploadedFiles: React.Dispatch<React.SetStateAction<UploadedFile[]>>;
    onOcrProcess: () => void;
    isOcrLoading: boolean;
    onAnalyze: () => void;
    isReadyForAnalysis: boolean;
    isAnalyzeLoading: boolean;
    analyzeTooltip: string;
    onExport: (type: 'evidence', lang: 'en' | 'vi') => void;
    evidenceLanguage: 'en' | 'vi';
    setEvidenceLanguage: (lang: 'en' | 'vi') => void;
    textareaRef: React.RefObject<HTMLTextAreaElement | null>;

    tags?: EvidenceTag[];
    onAddTag?: (tag: EvidenceTag) => void;
    selectedClauses?: string[];

    standards?: StandardsData;
    standardKey?: string;
    matrixData?: Record<string, MatrixRow[]>;
    setMatrixData?: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;

    // NEW FOR MULTI-DEPT
    availableDepartments?: string[];
    activeDepartment?: string;
    setActiveDepartment?: (dept: string) => void;
}

export const EvidenceView: React.FC<EvidenceViewProps> = ({
    evidence, setEvidence, uploadedFiles, setUploadedFiles,
    onOcrProcess, isOcrLoading, onAnalyze, isReadyForAnalysis,
    isAnalyzeLoading, analyzeTooltip, onExport, evidenceLanguage, setEvidenceLanguage,
    textareaRef, tags = [], onAddTag, selectedClauses = [],
    standards, standardKey, matrixData, setMatrixData,
    availableDepartments = [], activeDepartment = "", setActiveDepartment
}) => {
    // --- STATE ---
    const [isDragging, setIsDragging] = useState(false);
    const [isListening, setIsListening] = useState(false); 
    const [viewMode, setViewMode] = useState<'document' | 'matrix'>('document'); 
    const [isMatrixProcessing, setIsMatrixProcessing] = useState(false);
    const [selectionMenu, setSelectionMenu] = useState<{ x: number, y: number, text: string, start: number, end: number } | null>(null);

    // --- REFS ---
    const fileTargetRef = useRef<Record<string, { clauseId: string, rowId: string }>>({});
    const fileInputRef = useRef<HTMLInputElement>(null);
    const recognitionRef = useRef<any>(null);
    const matrixRef = useRef<EvidenceMatrixHandle>(null);

    // --- HELPER: INSERT DEPT MARKER ---
    const insertDeptMarker = () => {
        if (!activeDepartment) return;
        const marker = `\n\n=== 🏢 DEPARTMENT: ${activeDepartment.toUpperCase()} ===\n`;
        if (textareaRef.current) {
            const textarea = textareaRef.current;
            const start = textarea.selectionStart;
            const end = textarea.selectionEnd;
            const newText = evidence.substring(0, start) + marker + evidence.substring(end);
            setEvidence(newText);
            // Move cursor after
            setTimeout(() => {
                textarea.focus();
                textarea.setSelectionRange(start + marker.length, start + marker.length);
            }, 50);
        } else {
            setEvidence(prev => prev + marker);
        }
    };

    // --- HANDLERS: VOICE ---
    const toggleListening = useCallback(() => {
        if (isListening) {
            recognitionRef.current?.stop();
            setIsListening(false);
            return;
        }

        const SpeechRecognition = (window as any).SpeechRecognition || (window as any).webkitSpeechRecognition;
        if (!SpeechRecognition) {
            alert("Voice-to-Text is not supported in this browser (Try Chrome/Edge).");
            return;
        }

        // Matrix Mode Safety Check
        if (viewMode === 'matrix' && matrixRef.current && !matrixRef.current.getActiveRow()) {
            alert("Please click inside a Matrix cell first to dictate.");
            return;
        }

        try {
            const recognition = new SpeechRecognition();
            recognition.continuous = true;
            recognition.interimResults = true;
            // Configurable Language
            recognition.lang = evidenceLanguage === 'vi' ? 'vi-VN' : 'en-US';

            recognition.onstart = () => {
                // Auto-insert marker if needed
                if (viewMode === 'document' && activeDepartment) {
                    insertDeptMarker();
                }
            };

            recognition.onresult = (event: any) => {
                let finalTranscript = '';
                for (let i = event.resultIndex; i < event.results.length; ++i) {
                    if (event.results[i].isFinal) {
                        finalTranscript += event.results[i][0].transcript;
                    }
                }

                if (finalTranscript) {
                    const cleanText = finalTranscript.trim();
                    if (viewMode === 'matrix' && matrixRef.current) {
                        matrixRef.current.handleExternalDictation(cleanText);
                    } else {
                        setEvidence(prev => prev + (prev ? " " : "") + cleanText);
                    }
                }
            };

            recognition.onerror = (event: any) => {
                console.error("Speech Error", event.error);
                setIsListening(false);
            };

            recognition.onend = () => {
                setIsListening(false);
            };

            recognition.start();
            recognitionRef.current = recognition;
            setIsListening(true);
        } catch (e) {
            console.error("Failed to start recognition", e);
            setIsListening(false);
        }
    }, [isListening, viewMode, evidenceLanguage, setEvidence, activeDepartment]);

    // --- HANDLERS: FILE PROCESSING ---
    const processNewFiles = useCallback((files: File[], targetOverride?: { clauseId: string, rowId: string }) => {
        // Matrix Mode Handling
        if (viewMode === 'matrix') {
            const target = targetOverride || matrixRef.current?.getActiveRow();
            if (!target) {
                alert("Please select a specific cell in the Matrix to attach these files.");
                return;
            }

            const newFiles = files.map(f => {
                const id = Math.random().toString(36).substr(2, 9);
                fileTargetRef.current[id] = target;
                return { id, file: f, status: 'pending' as const };
            });
            setUploadedFiles(prev => [...prev, ...newFiles]);
            return;
        }

        // Document Mode Handling
        const newFiles = files.map(f => ({
            id: Math.random().toString(36).substr(2, 9),
            file: f,
            status: 'pending' as const
        }));
        setUploadedFiles(prev => [...prev, ...newFiles]);
    }, [viewMode, setUploadedFiles]);

    const handleMatrixOcrProcess = useCallback(async () => {
        const pendingFiles = uploadedFiles.filter(f => f.status === 'pending' || f.status === 'error');
        if (pendingFiles.length === 0) return;

        setIsMatrixProcessing(true);

        for (const fileEntry of pendingFiles) {
            try {
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'processing' } : f));

                let text = "";
                if (fileEntry.file.type.startsWith('image/')) {
                    const base64 = await fileToBase64(fileEntry.file);
                    text = await generateOcrContent("Transcribe text.", base64, fileEntry.file.type);
                } else if (fileEntry.file.type === 'application/pdf') {
                     text = "[PDF Content extracted via OCR would go here]"; 
                } else {
                    text = await fileEntry.file.text();
                }

                if (text && matrixRef.current) {
                    const target = fileTargetRef.current[fileEntry.id];
                    if (target) {
                        const header = `[File: ${fileEntry.file.name}]`;
                        matrixRef.current.insertEvidence(target.clauseId, target.rowId, `${header}\n${text}`);

                        setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'success', result: text } : f));
                        delete fileTargetRef.current[fileEntry.id];
                    } else {
                        throw new Error("Target row lost");
                    }
                } else {
                    throw new Error("No text extracted");
                }
            } catch (error: any) {
                console.error("Matrix OCR Error", error);
                setUploadedFiles(prev => prev.map(f => f.id === fileEntry.id ? { ...f, status: 'error', error: error.message || "Failed" } : f));
            }
        }
        setIsMatrixProcessing(false);
    }, [uploadedFiles, setUploadedFiles]);

    // --- HANDLERS: DRAG & DROP & TAGGING ---
    const handleDragOver = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(true); }, []);
    const handleDragLeave = useCallback((e: React.DragEvent) => { e.preventDefault(); setIsDragging(false); }, []);
    const handleDrop = useCallback((e: React.DragEvent) => {
        e.preventDefault();
        setIsDragging(false);
        if (e.dataTransfer.files && e.dataTransfer.files.length > 0) {
            processNewFiles(Array.from(e.dataTransfer.files));
        }
    }, [processNewFiles]);

    const handleTextSelect = useCallback((e: React.MouseEvent) => {
        if (viewMode === 'matrix' || !textareaRef.current) return;
        const start = textareaRef.current.selectionStart;
        const end = textareaRef.current.selectionEnd;

        if (start !== end) {
            setSelectionMenu({ 
                x: e.clientX, 
                y: e.clientY, 
                text: evidence.substring(start, end), 
                start, 
                end 
            });
        } else {
            setSelectionMenu(null);
        }
    }, [viewMode, evidence]);

    const confirmTag = (clauseId: string) => {
        if (selectionMenu && onAddTag) {
            onAddTag({
                id: `tag_${Date.now()}`,
                clauseId,
                text: selectionMenu.text,
                startIndex: selectionMenu.start,
                endIndex: selectionMenu.end,
                timestamp: Date.now()
            });
            setSelectionMenu(null);
        }
    };

    return (
        <div className="h-full flex flex-col gap-2 md:gap-4 animate-fade-in-up relative">

            {/* VIEW TOGGLE & CONTEXT SWITCHER */}
            <div className="flex flex-col md:flex-row gap-2 justify-between items-center py-2">
                {/* View Switcher */}
                <div className="flex bg-gray-100 dark:bg-slate-950 p-1 rounded-xl shadow-inner border border-gray-200 dark:border-slate-800">
                    <button 
                        onClick={() => setViewMode('document')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${viewMode === 'document' ? 'bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                    >
                        <Icon name="FileText" size={14}/> Document
                    </button>
                    <button 
                        onClick={() => setViewMode('matrix')}
                        className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all flex items-center gap-2 ${viewMode === 'matrix' ? 'bg-white dark:bg-slate-800 shadow-sm text-indigo-600 dark:text-white' : 'text-slate-500 hover:text-slate-700 dark:text-slate-400'}`}
                    >
                        <Icon name="LayoutList" size={14}/> Matrix
                    </button>
                </div>

                {/* Context Switcher (Only if Depts defined) */}
                {availableDepartments.length > 0 && setActiveDepartment && (
                    <div className="flex items-center gap-2 bg-indigo-50 dark:bg-indigo-900/20 px-3 py-1.5 rounded-xl border border-indigo-100 dark:border-indigo-800/50 shadow-sm animate-in fade-in slide-in-from-top-2">
                        <span className="text-[10px] font-bold text-indigo-600 dark:text-indigo-400 uppercase tracking-wider flex items-center gap-1">
                            <Icon name="Users" size={12}/> Global Context:
                        </span>
                        <select 
                            value={activeDepartment}
                            onChange={(e) => setActiveDepartment(e.target.value)}
                            className="bg-transparent text-xs font-bold text-slate-700 dark:text-white outline-none cursor-pointer hover:text-indigo-600 focus:ring-2 focus:ring-indigo-500/20 rounded"
                        >
                            {/* FIX: Explicit styling for options to ensure contrast in all browsers/modes */}
                            <option value="" className="text-slate-900 bg-white dark:bg-slate-800 dark:text-white">All Departments</option>
                            {availableDepartments.map(d => (
                                <option key={d} value={d} className="text-slate-900 bg-white dark:bg-slate-800 dark:text-white">{d}</option>
                            ))}
                        </select>
                        {activeDepartment && viewMode === 'document' && (
                            <button 
                                onClick={insertDeptMarker}
                                className="ml-2 px-2 py-0.5 bg-white dark:bg-slate-800 rounded text-[9px] font-bold text-indigo-600 dark:text-indigo-400 shadow-sm hover:scale-105 active:scale-95 transition-transform"
                                title="Insert Department Marker into Text"
                            >
                                + Marker
                            </button>
                        )}
                    </div>
                )}
            </div>

            <div className="flex-1 flex flex-col gap-2 md:gap-4 min-h-0 relative">

                {/* FLOATING TAG MENU */}
                {selectionMenu && selectedClauses && selectedClauses.length > 0 && viewMode === 'document' && (
                    <div 
                        className="fixed z-[9999] bg-slate-900/90 backdrop-blur-md text-white p-2.5 rounded-xl shadow-2xl flex flex-col gap-2 animate-in zoom-in-95 duration-200 border border-slate-700/50 ring-1 ring-white/10 max-w-[200px]"
                        style={{ top: selectionMenu.y - 120, left: Math.min(selectionMenu.x - 100, window.innerWidth - 220) }}
                    >
                        <div className="flex justify-between items-center border-b border-slate-700/50 pb-1.5 mb-1">
                            <span className="text-[10px] font-bold uppercase tracking-wider text-slate-300 flex items-center gap-1">
                                <Icon name="Tag" size={10}/> Tag As:
                            </span>
                            <button onClick={() => setSelectionMenu(null)} className="text-slate-400 hover:text-white bg-white/10 rounded-full p-0.5"><Icon name="X" size={10}/></button>
                        </div>
                        <div className="flex flex-wrap gap-1.5 justify-start max-h-[150px] overflow-y-auto custom-scrollbar">
                            {selectedClauses.map(clauseId => (
                                <button 
                                    key={clauseId}
                                    onClick={() => confirmTag(clauseId)}
                                    className="text-[10px] font-mono font-bold bg-indigo-600 hover:bg-indigo-50 text-white px-2 py-1 rounded-lg transition-all active:scale-95 shadow-sm border border-indigo-500 hover:border-indigo-400"
                                >
                                    {clauseId}
                                </button>
                            ))}
                        </div>
                        <div className="absolute bottom-[-6px] left-1/2 -translate-x-1/2 w-3 h-3 bg-slate-900/90 rotate-45 border-r border-b border-slate-700/50"></div>
                    </div>
                )}

                {/* MAIN CONTENT AREA */}
                <div
                    className={`flex-1 bg-white dark:bg-slate-900 rounded-3xl shadow-sm border overflow-hidden flex flex-col relative group transition-all duration-300 dark:shadow-[0_0_0_1px_rgba(255,255,255,0.05),0_4px_6px_-1px_rgba(0,0,0,0.5)] ${isDragging ? 'border-indigo-500 ring-4 ring-indigo-500/20 bg-indigo-50/10' : 'border-gray-100 dark:border-transparent'}`}
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                >
                    {isDragging && (
                        <div className="absolute inset-0 bg-indigo-500/10 backdrop-blur-[2px] z-50 flex flex-col items-center justify-center pointer-events-none animate-in fade-in zoom-in-95 duration-200">
                            <div className="p-6 rounded-full bg-white dark:bg-slate-900 shadow-2xl border-4 border-dashed border-indigo-500">
                                <Icon name="UploadCloud" size={48} className="text-indigo-600 animate-bounce" />
                            </div>
                            <h3 className="mt-4 text-xl font-black text-indigo-700 dark:text-indigo-400 uppercase tracking-widest text-center">Drop Files to Extract<br /><span className="text-sm font-normal normal-case">(Images, PDF, TXT)</span></h3>
                        </div>
                    )}

                    {viewMode === 'document' ? (
                        <textarea
                            ref={textareaRef}
                            className="flex-1 w-full h-full p-4 pb-6 bg-transparent resize-none focus:outline-none text-slate-700 dark:text-slate-300 font-medium text-sm leading-relaxed text-justify break-words whitespace-pre-wrap selection:bg-indigo-200 dark:selection:bg-indigo-900/60"
                            placeholder="Paste audit evidence here or use Voice Dictation..."
                            value={evidence}
                            onChange={(e) => setEvidence(e.target.value)}
                            onPaste={(e) => {
                                if (e.clipboardData.files.length > 0) {
                                    e.preventDefault();
                                    processNewFiles(Array.from(e.clipboardData.files));
                                }
                            }}
                            onMouseUp={handleTextSelect} 
                        />
                    ) : (
                        standards && standardKey && standards[standardKey] && matrixData && setMatrixData ? (
                            <div className="flex-1 w-full h-full bg-gray-50/30 dark:bg-slate-950/30 p-2">
                                <EvidenceMatrix 
                                    ref={matrixRef}
                                    standard={standards[standardKey]}
                                    selectedClauses={selectedClauses}
                                    matrixData={matrixData}
                                    setMatrixData={setMatrixData}
                                    onPasteFiles={processNewFiles}
                                    activeDepartment={activeDepartment} 
                                    availableDepartments={availableDepartments} // Pass full list for per-cell switching
                                />
                            </div>
                        ) : (
                            <div className="flex-1 flex items-center justify-center text-slate-400">
                                Please select a Standard to use Matrix Mode.
                            </div>
                        )
                    )}

                    {/* Floating Tags Indicator */}
                    {tags.length > 0 && viewMode === 'document' && (
                        <div className="absolute bottom-4 right-4 pointer-events-none opacity-60 group-hover:opacity-100 transition-opacity">
                            <div className="bg-white/90 dark:bg-slate-800/90 backdrop-blur-sm border border-indigo-100 dark:border-indigo-900/50 text-indigo-600 dark:text-indigo-300 text-[10px] font-bold px-3 py-1.5 rounded-full shadow-lg flex items-center gap-2">
                                <Icon name="Tag" size={12}/>
                                {tags.length} Evidence Tags
                            </div>
                        </div>
                    )}
                </div>

                {/* UPLOAD QUEUE */}
                {uploadedFiles.length > 0 && (
                    <div className="flex-shrink-0 p-3 bg-gray-50 dark:bg-slate-900 border border-gray-200 dark:border-white/5 rounded-2xl animate-in slide-in-from-bottom-5 duration-300 dark:shadow-inner">
                        {viewMode === 'matrix' && (
                            <div className="mb-2 text-[10px] font-bold text-indigo-500 uppercase tracking-widest px-1">
                                Matrix Queue: Files will attach to active cells
                            </div>
                        )}
                        <div className="flex gap-3 overflow-x-auto custom-scrollbar pb-2">
                            {uploadedFiles.map((fileEntry) => (
                                <div key={fileEntry.id} className={`relative group flex-shrink-0 w-24 h-24 bg-white dark:bg-slate-800 rounded-xl shadow-sm border overflow-hidden transition-all duration-300 dark:shadow-lg ${fileEntry.status === 'error' ? 'border-red-500 ring-2 ring-red-500/20' : 'border-gray-100 dark:border-white/5'}`}>
                                    {fileEntry.file.type.startsWith('image/') ? (
                                        <img src={URL.createObjectURL(fileEntry.file)} alt="preview" className={`w-full h-full object-cover transition-opacity ${fileEntry.status === 'processing' ? 'opacity-30' : 'opacity-80 group-hover:opacity-100'}`} />
                                    ) : (
                                        <div className="w-full h-full flex flex-col items-center justify-center bg-indigo-50 dark:bg-indigo-900/20 p-2 text-center">
                                            <Icon name={fileEntry.file.type === 'application/pdf' ? 'FileText' : 'Book'} size={24} className="text-indigo-600 dark:text-indigo-400 mb-1" />
                                            <span className="text-[8px] font-bold text-indigo-700 dark:text-indigo-300 truncate w-full">{fileEntry.file.name}</span>
                                        </div>
                                    )}

                                    {fileEntry.status === 'processing' && (
                                        <div className="absolute inset-0 flex items-center justify-center bg-white/40 dark:bg-black/40">
                                            <Icon name="Loader" className="animate-spin text-indigo-600" size={24} />
                                        </div>
                                    )}
                                    {fileEntry.status === 'success' && (
                                        <div className="absolute top-1 right-1 bg-emerald-500 text-white rounded-full p-0.5 shadow-sm">
                                            <Icon name="CheckThick" size={10} />
                                        </div>
                                    )}
                                    {fileEntry.status === 'error' && (
                                        <div className="absolute inset-0 flex flex-col items-center justify-center bg-red-50/80 dark:bg-red-950/80 p-1 text-center">
                                            <Icon name="AlertCircle" size={20} className="text-red-600" />
                                            <span className="text-[7px] font-black text-red-600 uppercase leading-tight mt-1">{fileEntry.error || 'Err'}</span>
                                        </div>
                                    )}

                                    <div className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 transition-opacity flex items-center justify-center z-20">
                                        <button onClick={() => setUploadedFiles(prev => prev.filter(f => f.id !== fileEntry.id))} className="bg-red-500 hover:bg-red-600 text-white rounded-full p-1.5 shadow-lg transform scale-90 hover:scale-110 transition-all duration-200"><Icon name="X" size={14} /></button>
                                    </div>
                                </div>
                            ))}
                            <div className="flex-shrink-0 w-24 h-24 flex items-center justify-center">
                                <button 
                                    onClick={viewMode === 'matrix' ? handleMatrixOcrProcess : onOcrProcess} 
                                    disabled={(isOcrLoading || isMatrixProcessing) || !uploadedFiles.some(f => f.status === 'pending' || f.status === 'error')} 
                                    className="w-full h-full bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl shadow-lg shadow-indigo-500/30 flex flex-col items-center justify-center gap-2 transition-all active:scale-95 disabled:opacity-50 hover:scale-105 duration-300"
                                >
                                    {(isOcrLoading || isMatrixProcessing) ? <Icon name="Loader" className="animate-spin" size={24} /> : <Icon name="ScanText" size={24} />}
                                    <span className="text-[10px] font-bold">Process</span>
                                </button>
                            </div>
                        </div>
                    </div>
                )}
            </div>

            {/* ACTION TOOLBAR - VERTICALLY CENTERED */}
            <div className="flex-shrink-0 flex flex-row items-center md:justify-end gap-2 md:gap-3 w-full py-2">
                <div className="flex-none w-[52px] md:w-auto">
                    <input type="file" ref={fileInputRef} className="hidden" accept="image/*,application/pdf,text/plain" multiple onChange={(e) => e.target.files && processNewFiles(Array.from(e.target.files))} />
                    <button onClick={() => fileInputRef.current?.click()} className={`w-full h-[52px] md:w-auto md:px-4 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm border whitespace-nowrap ${uploadedFiles.length > 0 ? 'bg-indigo-50 dark:bg-indigo-900/20 border-indigo-200 dark:border-indigo-800 text-indigo-600 dark:text-indigo-400' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:border-indigo-500'}`} title={viewMode === 'matrix' ? "Upload to Active Matrix Cell" : "Upload Files"}>
                        <Icon name={uploadedFiles.length > 0 ? "Demo1_MultiFiles" : "Demo8_GridPlus"} size={20} />
                        <span className="hidden md:inline">Upload</span>
                    </button>
                </div>

                <button
                    onClick={toggleListening}
                    className={`flex-none w-[52px] md:w-auto md:px-4 h-[52px] rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm border whitespace-nowrap ${isListening ? 'bg-red-50 dark:bg-red-900/20 border-red-200 dark:border-red-800 text-red-600 dark:text-red-400 animate-pulse' : 'bg-white dark:bg-slate-800 border-gray-200 dark:border-slate-700 text-slate-700 dark:text-slate-200 hover:border-indigo-500'}`}
                    title={isListening ? "Click to Stop" : `Start Dictation (${evidenceLanguage.toUpperCase()})`}
                >
                    <Icon name="Mic" size={20} className={isListening ? "animate-pulse" : ""} />
                    <span className="hidden md:inline">
                        {isListening ? `Recording (${evidenceLanguage.toUpperCase()})...` : `Dictate (${evidenceLanguage.toUpperCase()})`}
                    </span>
                </button>

                <button onClick={onAnalyze} disabled={!isReadyForAnalysis} title={analyzeTooltip} className={`flex-1 md:flex-none md:w-auto md:px-6 h-[52px] rounded-xl font-bold transition-all duration-300 flex items-center justify-center gap-2 shadow-lg whitespace-nowrap ${isReadyForAnalysis ? "btn-shrimp text-white active:scale-95" : "bg-gray-200 dark:bg-slate-800 text-slate-400 dark:text-slate-600 opacity-70 cursor-not-allowed border border-transparent"}`}>
                    {isAnalyzeLoading ? <SparkleLoader className="text-white" /> : <Icon name="Wand2" size={20} className="hidden md:block" />}
                    <span className="inline text-xs uppercase tracking-wider">Analyze</span>
                </button>

                <button onClick={() => onExport('evidence', evidenceLanguage)} disabled={!evidence || !evidence.trim()} className="flex-none md:w-auto px-3 md:px-4 h-[52px] bg-white dark:bg-slate-800 border border-gray-200 dark:border-slate-700 hover:border-indigo-500 text-slate-700 dark:text-slate-200 rounded-xl text-xs font-bold flex items-center justify-center gap-2 transition-all duration-300 active:scale-95 shadow-sm disabled:opacity-50 whitespace-nowrap dark:shadow-md">
                    <Icon name="Download" />
                    <span className="hidden md:inline">Export</span>
                    <div className="lang-pill-container ml-1" title="Select Input/Export Language">
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('en'); }} className={`lang-pill-btn ${evidenceLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={(e) => { e.stopPropagation(); setEvidenceLanguage('vi'); }} className={`lang-pill-btn ${evidenceLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                </button>
            </div>
        </div>
    );
};

import React, { useEffect, useState, useMemo, useImperativeHandle, forwardRef, useCallback, useRef } from 'react';
import { Icon } from '../UI';
import { Clause, Standard, MatrixRow } from '../../types';
import { copyToClipboard, serializeMatrixData } from '../../utils';

// --- TYPES ---
export interface EvidenceMatrixHandle {
    insertEvidence: (clauseId: string, rowId: string, text: string) => void;
    handleExternalDictation: (text: string) => void;
    getActiveRow: () => { clauseId: string, rowId: string } | null;
}

interface EvidenceMatrixProps {
    standard: Standard;
    selectedClauses: string[];
    matrixData: Record<string, MatrixRow[]>;
    setMatrixData: React.Dispatch<React.SetStateAction<Record<string, MatrixRow[]>>>;
    onPasteFiles?: (files: File[], target: { clauseId: string, rowId: string }) => void;
    activeDepartment?: string;
    availableDepartments?: string[]; // NEW PROP
}

// --- SUB-COMPONENT: MATRIX ROW ---
interface MatrixRowItemProps {
    row: MatrixRow;
    clauseId: string;
    isActive: boolean;
    isProcessing: boolean;
    splitRatio: number; 
    activeDepartment?: string;
    availableDepartments: string[]; // NEW
    onInputChange: (clauseId: string, rowId: string, value: string) => void;
    onFocus: (clauseId: string, rowId: string) => void;
    onPaste: (e: React.ClipboardEvent, clauseId: string, rowId: string) => void;
    onStamp: (clauseId: string, rowId: string, dept: string) => void;
}

const MatrixRowItem = React.memo(({ row, clauseId, isActive, isProcessing, splitRatio, activeDepartment, availableDepartments, onInputChange, onFocus, onPaste, onStamp }: MatrixRowItemProps) => {
    // Scroll text area to bottom on stamp
    const textAreaRef = useRef<HTMLTextAreaElement>(null);

    // Auto-scroll when content length changes significantly (e.g. stamp added)
    useEffect(() => {
        if (isActive && textAreaRef.current) {
            const el = textAreaRef.current;
            // Only scroll if we are near the bottom or it's a fresh insert
            if (el.selectionStart === el.value.length) {
                el.scrollTop = el.scrollHeight;
            }
        }
    }, [row.evidenceInput, isActive]);

    return (
        <div 
            className={`grid gap-4 items-start p-3 rounded-lg transition-colors group relative border border-transparent ${isActive ? 'bg-white dark:bg-slate-900 shadow-sm border-indigo-100 dark:border-indigo-900/30' : 'hover:bg-gray-50 dark:hover:bg-slate-800/30 hover:border-gray-100 dark:hover:border-slate-800'}`}
            style={{ gridTemplateColumns: `${splitRatio}% minmax(0, 1fr)` }}
        >
            <div className={`text-xs font-medium leading-relaxed pt-2 select-none break-words ${isActive ? 'text-indigo-900 dark:text-indigo-200' : 'text-slate-600 dark:text-slate-300'}`}>
                {row.requirement}
            </div>

            <div className="relative min-w-0 group/input">
                <textarea
                    ref={textAreaRef}
                    rows={3}
                    placeholder={isActive ? (activeDepartment ? `Typing for ${activeDepartment}... (Or click badge to switch)` : "Type evidence here...") : "Click to edit..."}
                    className={`w-full bg-gray-50 dark:bg-slate-950 border rounded-lg p-2 text-xs text-slate-800 dark:text-white outline-none transition-all resize-y min-h-[80px] shadow-sm 
                        ${isProcessing ? 'opacity-50 pointer-events-none' : ''} 
                        ${isActive 
                            ? 'border-indigo-500 ring-2 ring-indigo-500/20 bg-white dark:bg-slate-900 pt-8' // Extra padding top for toolbar
                            : 'border-gray-200 dark:border-slate-700 focus:border-indigo-400'
                        }`}
                    value={row.evidenceInput}
                    onChange={(e) => onInputChange(clauseId, row.id, e.target.value)}
                    onFocus={() => onFocus(clauseId, row.id)}
                    onPaste={(e) => onPaste(e, clauseId, row.id)}
                />

                {/* --- IN-PLACE CONTEXT TOOLBAR --- */}
                {isActive && availableDepartments.length > 0 && (
                    <div className="absolute top-0 right-0 left-0 h-7 flex items-center justify-end px-2 gap-1 bg-gradient-to-b from-white via-white to-transparent dark:from-slate-900 dark:via-slate-900 rounded-t-lg z-20 border-b border-indigo-50 dark:border-slate-800/50">
                        <span className="text-[8px] font-bold text-slate-300 uppercase tracking-widest mr-1">Log Context:</span>
                        {availableDepartments.map(dept => (
                            <button
                                key={dept}
                                onClick={(e) => { 
                                    e.preventDefault(); 
                                    e.stopPropagation(); 
                                    onStamp(clauseId, row.id, dept); 
                                    textAreaRef.current?.focus();
                                }}
                                className={`px-1.5 py-0.5 rounded text-[9px] font-bold uppercase transition-all border shadow-sm ${dept === activeDepartment 
                                    ? 'bg-indigo-600 text-white border-indigo-600 shadow-indigo-500/30' 
                                    : 'bg-white dark:bg-slate-800 text-slate-500 dark:text-slate-400 border-gray-200 dark:border-slate-700 hover:border-indigo-400 hover:text-indigo-500'}`}
                                title={`Insert Header: [${dept}]`}
                            >
                                {dept}
                            </button>
                        ))}
                    </div>
                )}

                {/* Status Indicators */}
                {!isActive && row.status === 'supplied' && !isProcessing && (
                    <div className="absolute top-2 right-2 pointer-events-none transition-opacity duration-300">
                        <div className="bg-emerald-500/10 p-0.5 rounded-full">
                            <Icon name="CheckThick" size={10} className="text-emerald-600"/>
                        </div>
                    </div>
                )}

                {/* Processing Indicator */}
                {isProcessing && (
                    <div className="absolute bottom-2 right-2 flex items-center gap-2 px-2 py-1 bg-white dark:bg-slate-800 rounded-md shadow-sm border border-indigo-100 dark:border-slate-600 z-10 animate-in fade-in zoom-in">
                        <Icon name="Loader" className="animate-spin text-indigo-500" size={12}/>
                        <span className="text-[9px] font-bold text-indigo-500">Processing...</span>
                    </div>
                )}
            </div>
        </div>
    );
}, (prev, next) => {
    return (
        prev.row.evidenceInput === next.row.evidenceInput &&
        prev.row.status === next.row.status &&
        prev.isActive === next.isActive &&
        prev.isProcessing === next.isProcessing &&
        prev.splitRatio === next.splitRatio &&
        prev.activeDepartment === next.activeDepartment &&
        prev.availableDepartments.length === next.availableDepartments.length // Simple check for dept changes
    );
});

// --- MAIN COMPONENT ---
export const EvidenceMatrix = forwardRef<EvidenceMatrixHandle, EvidenceMatrixProps>(({
    standard, selectedClauses, matrixData, setMatrixData, onPasteFiles, activeDepartment, availableDepartments = []
}, ref) => {
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);

    // Resize State
    const [splitRatio, setSplitRatio] = useState(40); // Initial 40% for Requirement
    const [isResizing, setIsResizing] = useState(false);
    const containerRef = useRef<HTMLDivElement>(null);

    // Track focused row
    const [activeRow, setActiveRow] = useState<{ clauseId: string, rowId: string } | null>(null);
    const [processingRowId, setProcessingRowId] = useState<string | null>(null);

    // 1. Flatten Clauses (Memoized)
    const flatClauses = useMemo(() => {
        const all: Clause[] = [];
        const traverse = (list: Clause[]) => {
            list.forEach(c => {
                all.push(c);
                if(c.subClauses) traverse(c.subClauses);
            });
        };
        standard.groups.forEach(g => traverse(g.clauses));
        return all;
    }, [standard]);

    // 2. Initialize Matrix State (Effect)
    useEffect(() => {
        setMatrixData(currentMatrix => {
            const newMatrix = { ...currentMatrix };
            let updated = false;

            selectedClauses.forEach(clauseId => {
                if (!newMatrix[clauseId]) {
                    const clause = flatClauses.find(c => c.id === clauseId);
                    if (clause) {
                        const desc = clause.description || "";
                        const reqs = desc.length > 60 
                            ? desc.split(/(?:\. |\n)/).filter(s => s.trim().length > 5) 
                            : [desc];

                        newMatrix[clauseId] = reqs.map((req, idx) => ({
                            id: `${clauseId}_req_${idx}`,
                            requirement: req.trim(),
                            evidenceInput: "",
                            status: 'pending'
                        }));
                        updated = true;
                    }
                }
            });

            if (updated) {
                if(selectedClauses.length > 0 && expandedClauses.length === 0) {
                    setExpandedClauses([selectedClauses[0]]);
                }
                return newMatrix;
            }
            return currentMatrix;
        });
    }, [selectedClauses, flatClauses, setMatrixData]);

    // --- RESIZE HANDLERS ---
    const startResizing = useCallback((e: React.MouseEvent) => {
        e.preventDefault();
        setIsResizing(true);
        document.body.style.cursor = 'col-resize';
        document.body.style.userSelect = 'none';

        const handleMouseMove = (moveEvent: MouseEvent) => {
            if (containerRef.current) {
                const rect = containerRef.current.getBoundingClientRect();
                const relativeX = moveEvent.clientX - rect.left;
                const percentage = (relativeX / rect.width) * 100;
                setSplitRatio(Math.min(80, Math.max(20, percentage)));
            }
        };

        const handleMouseUp = () => {
            setIsResizing(false);
            document.body.style.cursor = '';
            document.body.style.userSelect = '';
            document.removeEventListener('mousemove', handleMouseMove);
            document.removeEventListener('mouseup', handleMouseUp);
        };

        document.addEventListener('mousemove', handleMouseMove);
        document.addEventListener('mouseup', handleMouseUp);
    }, []);

    // --- INPUT HANDLERS (Memoized) ---

    const updateRowData = useCallback((clauseId: string, rowId: string, textToAppend: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => {
                if (row.id === rowId) {
                    const currentText = row.evidenceInput || "";
                    // Smart separator: if text exists and doesn't end with newline, add one.
                    const separator = currentText && !currentText.endsWith('\n') ? "\n" : "";
                    const newText = currentText + separator + textToAppend;
                    return { ...row, evidenceInput: newText, status: newText.trim() ? 'supplied' : 'pending' };
                }
                return row;
            })
        }));
    }, [setMatrixData]);

    const handleInputChange = useCallback((clauseId: string, rowId: string, value: string) => {
        setMatrixData(prev => ({
            ...prev,
            [clauseId]: prev[clauseId].map(row => 
                row.id === rowId 
                ? { ...row, evidenceInput: value, status: value.trim() ? 'supplied' : 'pending' } 
                : row
            )
        }));
    }, [setMatrixData]);

    const handlePaste = useCallback((e: React.ClipboardEvent, clauseId: string, rowId: string) => {
        const items = e.clipboardData.items;
        const files: File[] = [];

        for (let i = 0; i < items.length; i++) {
            if (items[i].kind === 'file') {
                const f = items[i].getAsFile();
                if (f) files.push(f);
            }
        }

        if (files.length > 0) {
            e.preventDefault();
            if (onPasteFiles) {
                if (activeDepartment) {
                    updateRowData(clauseId, rowId, `\n[Dept: ${activeDepartment}] Attaching files...`);
                }
                onPasteFiles(files, { clauseId, rowId });
            }
        }
    }, [onPasteFiles, activeDepartment, updateRowData]);

    const handleFocus = useCallback((clauseId: string, rowId: string) => {
        setActiveRow({ clauseId, rowId });
    }, []);

    // NEW: Handle Stamp Click - Formats nicely
    const handleStamp = useCallback((clauseId: string, rowId: string, dept: string) => {
        const stamp = `\n=== 🏢 ${dept.toUpperCase()} ===\n`;
        updateRowData(clauseId, rowId, stamp);
    }, [updateRowData]);

    // --- EXPOSED API ---
    useImperativeHandle(ref, () => ({
        insertEvidence: (clauseId, rowId, text) => {
            const prefix = activeDepartment ? `[${activeDepartment}] ` : "";
            updateRowData(clauseId, rowId, prefix + text);
        },
        handleExternalDictation: (text: string) => {
            if (activeRow) {
                const prefix = activeDepartment ? `[${activeDepartment}] ` : "";
                updateRowData(activeRow.clauseId, activeRow.rowId, prefix + text);
            }
        },
        getActiveRow: () => activeRow
    }));

    const handleCopyMatrixToClipboard = () => {
        const text = serializeMatrixData(matrixData, selectedClauses);
        if(text) {
            copyToClipboard(text);
            alert("Matrix data copied to clipboard as Table!"); 
        } else {
            alert("Matrix is empty.");
        }
    };

    const toggleExpand = (id: string) => {
        setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    };

    if (selectedClauses.length === 0) {
        return (
            <div className="h-full flex flex-col items-center justify-center text-slate-400 bg-gray-50/50 dark:bg-slate-900/50 rounded-3xl border border-dashed border-gray-200 dark:border-slate-800">
                <Icon name="LayoutList" size={48} className="mb-4 opacity-50"/>
                <p className="text-sm font-medium">Select clauses from the sidebar to start mapping evidence.</p>
            </div>
        );
    }

    return (
        <div className="h-full flex flex-col relative animate-fade-in-up" ref={containerRef}>
            <div className="flex-shrink-0 flex justify-between items-center mb-2 px-1">
                 <button 
                    onClick={handleCopyMatrixToClipboard}
                    className="ml-auto text-[10px] font-bold text-slate-500 hover:text-indigo-600 dark:text-slate-400 dark:hover:text-indigo-400 flex items-center gap-1 bg-white dark:bg-slate-800 px-2 py-1 rounded shadow-sm border border-gray-100 dark:border-slate-700 hover:border-indigo-200 transition-colors"
                    title="Export to Clipboard"
                 >
                    <Icon name="Copy" size={12}/> Copy Matrix Table
                 </button>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar space-y-4 p-1 pb-10">
                {selectedClauses.map(clauseId => {
                    const clause = flatClauses.find(c => c.id === clauseId);
                    const rows = matrixData[clauseId] || [];
                    const isExpanded = expandedClauses.includes(clauseId);
                    if (!clause) return null;

                    const filledCount = rows.filter(r => r.status === 'supplied').length;
                    const progress = Math.round((filledCount / (rows.length || 1)) * 100);

                    return (
                        <div key={clauseId} className="bg-white dark:bg-slate-900 rounded-xl border border-gray-200 dark:border-slate-800 shadow-sm overflow-hidden transition-all duration-300">
                            {/* Header */}
                            <div 
                                className="flex items-center justify-between p-3 bg-gray-50/80 dark:bg-slate-800/50 cursor-pointer hover:bg-gray-100 dark:hover:bg-slate-800 transition-colors select-none"
                                onClick={() => toggleExpand(clauseId)}
                            >
                                <div className="flex items-center gap-3">
                                    <span className="text-xs font-black text-indigo-600 dark:text-indigo-400 bg-indigo-50 dark:bg-indigo-900/30 px-2 py-1 rounded border border-indigo-100 dark:border-indigo-800/50">
                                        {clause.code}
                                    </span>
                                    <h4 className="text-xs font-bold text-slate-700 dark:text-slate-200">{clause.title}</h4>
                                </div>
                                <div className="flex items-center gap-3">
                                    <div className="w-16 h-1.5 bg-gray-200 dark:bg-slate-700 rounded-full overflow-hidden">
                                        <div 
                                            className={`h-full rounded-full transition-all duration-500 ease-out ${progress === 100 ? 'bg-emerald-500' : 'bg-indigo-500'}`} 
                                            style={{ width: `${progress}%` }}
                                        />
                                    </div>
                                    <Icon name={isExpanded ? "ChevronUp" : "ChevronDown"} size={14} className="text-slate-400"/>
                                </div>
                            </div>

                            {/* Body */}
                            {isExpanded && (
                                <div className="p-3 border-t border-gray-100 dark:border-slate-800 animate-accordion-down">
                                    {/* Resizable Header */}
                                    <div 
                                        className="grid gap-4 mb-2 px-3 relative"
                                        style={{ gridTemplateColumns: `${splitRatio}% minmax(0, 1fr)` }}
                                    >
                                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider truncate">Requirement Breakdown</span>
                                        <span className="text-[9px] font-bold text-slate-400 uppercase tracking-wider truncate">Verified Evidence</span>

                                        {/* Resize Handle */}
                                        <div 
                                            className="absolute top-0 bottom-0 w-4 cursor-col-resize flex justify-center group z-10 hover:z-20"
                                            style={{ left: `calc(${splitRatio}% + 0.5rem - 8px)` }} // Center over the gap (gap-4 is 1rem)
                                            onMouseDown={startResizing}
                                            onClick={(e) => e.stopPropagation()}
                                        >
                                            <div className={`w-1 h-full rounded-full transition-colors duration-200 ${isResizing ? 'bg-indigo-500' : 'bg-transparent group-hover:bg-indigo-200 dark:group-hover:bg-indigo-800'}`}></div>
                                        </div>
                                    </div>

                                    <div className="space-y-1">
                                        {rows.map((row) => (
                                            <MatrixRowItem
                                                key={row.id}
                                                row={row}
                                                clauseId={clauseId}
                                                isActive={activeRow?.rowId === row.id}
                                                isProcessing={processingRowId === row.id}
                                                splitRatio={splitRatio}
                                                activeDepartment={activeDepartment} 
                                                availableDepartments={availableDepartments} // Pass departments
                                                onInputChange={handleInputChange}
                                                onFocus={handleFocus}
                                                onPaste={handlePaste}
                                                onStamp={handleStamp}
                                            />
                                        ))}
                                    </div>
                                </div>
                            )}
                        </div>
                    );
                })}
            </div>
        </div>
    );
});
